"use server";

import { db } from "@/lib/db";
import { users, ngos, projects, documents, activityLogs, teamMembers, boardMembers, beneficiaries } from "@/lib/schema";
import { eq, desc, asc, sql } from "drizzle-orm";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth-options";
import { revalidatePath } from "next/cache";

export async function getAdminDashboardData() {
    const session = await getServerSession(authOptions);
    if (!session?.user?.id) return { error: "Unauthorized" };

    try {
        // Basic Counts
        const ngosCountRes = await db.select({ count: sql<number>`count(*)` }).from(ngos);
        const totalNGOs = ngosCountRes[0]?.count || 0;

        const usersCountRes = await db.select({ count: sql<number>`count(*)` }).from(users);
        const totalUsers = usersCountRes[0]?.count || 0;

        const projectsRes = await db.select().from(projects);
        const activeProjects = projectsRes.filter(p => p.status === 'active').length;

        const fundsRes = await db.select({ total: sql<number>`sum(${projects.raisedAmount})` }).from(projects);
        const totalFundsRaw = fundsRes[0]?.total || 0;
        // Format totalFunds (e.g. ₹52.4Cr)
        let totalFundsFormatted = `₹${totalFundsRaw}`;
        if (totalFundsRaw >= 10000000) {
            totalFundsFormatted = `₹${(totalFundsRaw / 10000000).toFixed(1)}Cr`;
        } else if (totalFundsRaw >= 100000) {
            totalFundsFormatted = `₹${(totalFundsRaw / 100000).toFixed(1)}L`;
        } else {
            totalFundsFormatted = `₹${totalFundsRaw.toLocaleString('en-IN')}`;
        }

        const stats = [
            { id: "ngos", label: "Total NGOs", value: totalNGOs.toString(), sub: "Registered platform-wide", change: "...", color: "bg-blue-500" },
            { id: "users", label: "Total Users", value: totalUsers.toString(), sub: "Across platform", change: "...", color: "bg-teal-500" },
            { id: "projects", label: "Active Projects", value: activeProjects.toString(), sub: "Currently running", change: "...", color: "bg-orange-500" },
            { id: "funds", label: "Total Funds Raised", value: totalFundsFormatted, sub: "Lifetime", change: "...", color: "bg-purple-500" },
        ];

        // Pending Actions (e.g., Unverified NGOs, Pending Documents)
        const pendingNgos = await db.select().from(ngos).where(eq(ngos.verified, false)).limit(3);
        const pendingDocs = await db.select().from(documents).where(eq(documents.status, 'pending')).limit(3);

        const pendingActions = [
            ...pendingNgos.map(n => ({
                id: `ngo-${n.id}`,
                priority: "high",
                type: "NGO Verification",
                title: n.name,
                desc: "New NGO registration pending verification",
                time: n.createdAt.toLocaleDateString(),
                action: "Verify Now",
                link: `/dashboard/admin/ngo-management/${n.id}`
            })),
            ...pendingDocs.map(d => ({
                id: `doc-${d.id}`,
                priority: "medium",
                type: "Document Review",
                title: d.name,
                desc: `Document from NGO ID ${d.ngoId}`,
                time: d.createdAt.toLocaleDateString(),
                action: "Review",
                link: `/dashboard/admin/document-approval/${d.id}`
            }))
        ];

        // Recent Activities (latest logs or creations)
        const activities = await db.select().from(activityLogs).orderBy(desc(activityLogs.createdAt)).limit(5);
        const formattedActivities = activities.map(a => ({
            id: a.id,
            name: `NGO ID: ${a.ngoId}`, // In real app, join with NGO table
            event: a.action,
            time: a.createdAt.toLocaleDateString(),
            color: "bg-blue-500"
        }));

        // Top NGOs (mock scoring for now based on details + verification)
        const nList = await db.select().from(ngos).where(eq(ngos.verified, true)).limit(5);
        const topNGOs = await Promise.all(nList.map(async (n, idx) => {

            // Fetch dynamically
            const ngoProjects = await db.select().from(projects).where(eq(projects.ngoId, n.id));
            const ngoBeneficiaries = await db.select({ count: sql<number>`count(*)` }).from(beneficiaries).where(eq(beneficiaries.ngoId, n.id));

            const totalNGOFunds = ngoProjects.reduce((sum, p) => sum + (p.raisedAmount || 0), 0);
            let formattedFunds = `₹${totalNGOFunds}`;
            if (totalNGOFunds >= 10000000) {
                formattedFunds = `₹${(totalNGOFunds / 10000000).toFixed(1)}Cr`;
            } else if (totalNGOFunds >= 100000) {
                formattedFunds = `₹${(totalNGOFunds / 100000).toFixed(1)}L`;
            } else {
                formattedFunds = `₹${totalNGOFunds.toLocaleString('en-IN')}`;
            }

            return {
                id: n.id,
                initials: n.name.substring(0, 2).toUpperCase(),
                name: n.name,
                sub: n.verified ? "Verified NGO" : "Unverified",
                score: 80 + (ngoProjects.length * 5) + (totalNGOFunds > 100000 ? 10 : 0), // Base score + bonuses
                projects: ngoProjects.length,
                beneficiaries: (ngoBeneficiaries[0]?.count || 0).toString(),
                funds: formattedFunds,
                rating: 4.5 + (Math.random() * 0.5),
                color: ["bg-[#1572A1]", "bg-green-600", "bg-teal-600", "bg-amber-600"][idx % 4]
            };
        }));

        const summaryCards = [
            { icon: "✓", label: "Verified NGOs", value: nList.length.toString(), sub: "Registered", color: "from-green-500 to-emerald-600" },
            { icon: "⏱", label: "Pending Verifications", value: pendingNgos.length.toString(), sub: "Requires attention", color: "from-amber-500 to-yellow-600" },
            { icon: "!", label: "Flagged Issues", value: "0", sub: "None at the moment", color: "from-red-500 to-rose-600" },
        ];

        return {
            stats,
            pendingActions,
            recentActivities: formattedActivities,
            topNGOs,
            summaryCards
        };

    } catch (error) {
        console.error("Error fetching admin dashboard data:", error);
        return { error: "Failed to fetch admin data." };
    }
}

export async function verifyNGO(ngoId: number) {
    const session = await getServerSession(authOptions);
    if (!session?.user?.id || (session.user as any).role !== 'admin') {
        return { error: "Unauthorized" };
    }

    try {
        await db.update(ngos).set({ verified: true, updatedAt: new Date() }).where(eq(ngos.id, ngoId));
        revalidatePath('/dashboard/admin');
        revalidatePath('/dashboard/admin/ngo-management');
        return { success: true };
    } catch (e) {
        console.error(e);
        return { error: "Failed to verify NGO" };
    }
}

export async function getAdminDocuments() {
    const session = await getServerSession(authOptions);
    if (!session?.user?.id || (session.user as any).role !== 'admin') {
        return { error: "Unauthorized" };
    }

    try {
        const docs = await db.select({
            id: documents.id,
            name: documents.name,
            type: documents.type,
            category: documents.category,
            url: documents.url,
            status: documents.status,
            expiryDate: documents.expiryDate,
            createdAt: documents.createdAt,
            ngoName: ngos.name,
            ngoId: documents.ngoId // Use document's ngoId, not the joined one which might be null
        })
            .from(documents)
            .leftJoin(ngos, eq(documents.ngoId, ngos.id))
            .orderBy(desc(documents.createdAt));

        // Map over the results to ensure fallback values for missing NGO references
        const mappedDocs = docs.map(d => ({
            ...d,
            ngoName: d.ngoName || `NGO ID: ${d.ngoId || 'Unknown'}`,
            ngoId: d.ngoId || 0
        }));

        return { data: mappedDocs };
    } catch (error) {
        console.error("Error fetching admin documents:", error);
        return { error: "Failed to fetch documents." };
    }
}

import { notifications } from '@/lib/schema';

export async function updateDocumentStatus(docId: number, status: string, rejectionReason?: string) {
    const session = await getServerSession(authOptions);
    if (!session?.user?.id || (session.user as any).role !== 'admin') {
        return { error: "Unauthorized" };
    }

    try {
        // Here you would also add rejectionReason to schema if needed, for now we just change status
        // and optionally create an activity log for the rejection reason.
        await db.update(documents).set({ status, updatedAt: new Date() }).where(eq(documents.id, docId));

        const doc = await db.select({
            id: documents.id,
            name: documents.name,
            ngoId: documents.ngoId,
            ownerId: ngos.ownerId
        }).from(documents)
            .leftJoin(ngos, eq(documents.ngoId, ngos.id))
            .where(eq(documents.id, docId))
            .limit(1);

        if (doc[0]) {
            const message = `Your document '${doc[0].name}' was ${status}.${rejectionReason ? ` Reason: ${rejectionReason}` : ''}`;
            await db.insert(activityLogs).values({
                ngoId: doc[0].ngoId,
                action: `Document ${status}`,
                details: message
            });

            // Log notification to DB for polling
            if (doc[0].ownerId) {
                await db.insert(notifications).values({
                    userId: doc[0].ownerId,
                    title: `Document ${status.toUpperCase()}`,
                    message: message,
                });
            }
        }

        revalidatePath('/dashboard/admin/document-approval');
        return { success: true };
    } catch (error) {
        console.error("Error updating document status:", error);
        return { error: "Failed to update document status." };
    }
}

export async function getAdminNGOs() {
    const session = await getServerSession(authOptions);
    if (!session?.user?.id || (session.user as any).role !== 'admin') {
        return { error: "Unauthorized" };
    }

    try {
        const ngoList = await db.select().from(ngos).orderBy(desc(ngos.createdAt));

        // We could write a complex JOIN but a map is safer and fast enough for <1000 items usually
        const data = await Promise.all(ngoList.map(async (n, idx) => {
            const projectsRes = await db.select().from(projects).where(eq(projects.ngoId, n.id));
            const totalFunds = projectsRes.reduce((sum, p) => sum + (p.raisedAmount || 0), 0);

            // Format totalFunds
            let totalFundsFormatted = `₹${totalFunds}`;
            if (totalFunds >= 10000000) {
                totalFundsFormatted = `₹${(totalFunds / 10000000).toFixed(1)}Cr`;
            } else if (totalFunds >= 100000) {
                totalFundsFormatted = `₹${(totalFunds / 100000).toFixed(1)}L`;
            } else {
                totalFundsFormatted = `₹${totalFunds.toLocaleString('en-IN')}`;
            }

            const owner = await db.select({ email: users.email, phone: users.phoneNumber }).from(users).where(eq(users.id, n.ownerId)).limit(1);

            return {
                id: n.id,
                initials: n.name.substring(0, 2).toUpperCase(),
                name: n.name,
                reg: n.registrationNumber || "N/A",
                email: owner[0]?.email || "N/A",
                phone: owner[0]?.phone || "N/A",
                location: n.headquarters || "Unknown",
                status: n.verified ? "Verified" : "Pending",
                score: n.verified ? Math.floor(Math.random() * 20) + 80 : null, // mock score,
                projects: projectsRes.length,
                beneficiaries: "0", // Could do beneficiaries lookup
                funds: totalFundsFormatted,
                lastActive: new Date(n.updatedAt).toLocaleDateString(),
                color: ["bg-[#1572A1]", "bg-green-600", "bg-teal-600", "bg-amber-600"][idx % 4]
            };
        }));

        return { data };
    } catch (error) {
        console.error("Error fetching NGOs:", error);
        return { error: "Failed to fetch NGOs" };
    }
}

export async function deleteNGO(ngoId: number) {
    const session = await getServerSession(authOptions);
    if (!session?.user?.id || (session.user as any).role !== 'admin') {
        return { error: "Unauthorized" };
    }

    try {
        // Technically need to cascade delete but depends on DB constraints. We will just delete the NGO.
        await db.delete(ngos).where(eq(ngos.id, ngoId));
        revalidatePath('/dashboard/admin/ngo-management');
        return { success: true };
    } catch (err) {
        console.error(err);
        return { error: "Failed to delete NGO. Make sure all children records are deleted first or cascade is enabled." };
    }
}

export async function getAdminNGOById(ngoId: number) {
    const session = await getServerSession(authOptions);
    if (!session?.user?.id || (session.user as any).role !== 'admin') {
        return { error: "Unauthorized" };
    }

    try {
        const ngoList = await db.select().from(ngos).where(eq(ngos.id, ngoId)).limit(1);
        if (ngoList.length === 0) return { error: "NGO not found" };

        const n = ngoList[0];
        const owner = await db.select({ email: users.email, phone: users.phoneNumber }).from(users).where(eq(users.id, n.ownerId)).limit(1);
        const team = await db.select().from(teamMembers).where(eq(teamMembers.ngoId, ngoId));
        const board = await db.select().from(boardMembers).where(eq(boardMembers.ngoId, ngoId));

        return {
            id: n.id,
            name: n.name,
            type: n.type || "Trust",
            panNumber: n.panNumber || "",
            registrationNumber: n.registrationNumber || "",
            foundedYear: n.foundedYear || "",
            teamSize: n.teamSize || "",
            headquarters: n.headquarters || "",
            description: n.description || "",
            focusAreas: (n.focusAreas as string[]) || [],
            operationalStates: (n.operationalStates as string[]) || [],
            operationalDistricts: (n.operationalDistricts as string[]) || [],
            vision: n.vision || "",
            mission: n.mission || "",
            objectives: n.objectives || "",
            lat: n.lat || 0,
            lng: n.lng || 0,
            teamMembers: team || [],
            boardMembers: board || [],
            status: n.verified ? "Verified" : "Pending",
            email: owner[0]?.email || "N/A",
            phone: owner[0]?.phone || "N/A",
        };
    } catch (error) {
        console.error("Error fetching NGO by ID:", error);
        return { error: "Failed to fetch NGO details" };
    }
}

export async function updateAdminNGODetails(ngoId: number, data: any) {
    const session = await getServerSession(authOptions);
    if (!session?.user?.id || (session.user as any).role !== 'admin') {
        return { error: "Unauthorized" };
    }

    try {
        await db.update(ngos).set({
            name: data.name,
            registrationNumber: data.registrationNumber,
            panNumber: data.panNumber,
            headquarters: data.headquarters,
            updatedAt: new Date(),
        }).where(eq(ngos.id, ngoId));

        if (data.status) {
            await db.update(ngos).set({
                verified: data.status === "Verified",
                updatedAt: new Date(),
            }).where(eq(ngos.id, ngoId));
        }

        revalidatePath(`/dashboard/admin/ngo-management/${ngoId}`);
        revalidatePath(`/dashboard/admin/ngo-management/${ngoId}/edit`);
        revalidatePath(`/dashboard/admin/ngo-management`);
        return { success: true };
    } catch (error) {
        console.error("Error updating NGO specifics:", error);
        return { error: "Failed to update NGO details." };
    }
}

'use server';

import { db } from '@/lib/db';
import { users, ngos } from '@/lib/schema';

import { eq } from 'drizzle-orm';
import bcrypt from 'bcryptjs';
import { redirect } from 'next/navigation';
import { z } from 'zod';

const SignupSchema = z.object({
  name: z.string().min(2, { message: 'Name must be at least 2 characters long.' }),
  email: z.string().email({ message: 'Please enter a valid email.' }),
  password: z.string().min(6, { message: 'Password must be at least 6 characters long.' }),
  organizationName: z.string().min(2, { message: "Organization name is required." }),
});

export async function signup(prevState: any, formData: FormData) {
  const rawData = {
    name: formData.get('name'),
    email: formData.get('email'),
    password: formData.get('password'),
    organizationName: formData.get('organizationName'),
  };

  const validatedFields = SignupSchema.safeParse(rawData);

  if (!validatedFields.success) {
    return {
      errors: validatedFields.error.flatten().fieldErrors,
    };
  }

  const { name, email, password, organizationName } = validatedFields.data;

  // Check if user exists
  const existingUser = await db.select().from(users).where(eq(users.email, email));
  if (existingUser.length > 0) {
    return {
      errors: {
        email: ['User with this email already exists.'],
      },
    };
  }

  // Hash password
  const hashedPassword = await bcrypt.hash(password, 10);

  // Create user
  try {
    const [newUser] = await db.insert(users).values({
      name,
      email,
      password: hashedPassword,
      role: 'ngo', // Defaulting to NGO
      organizationName: organizationName,
      provider: 'credentials',
    }).returning({ id: users.id });

    // Create a shell NGO profile immediately to track onboarding progress
    if (newUser) {
      await db.insert(ngos).values({
        ownerId: newUser.id,
        name: organizationName,
        verified: false,
      });
    }
  } catch (error) {
    console.error('Signup Error:', error);
    return {
      message: 'Database Error: Failed to Create User.',
    };
  }

  redirect('/signin?success=Account created. Please log in.');
}

export async function logout() {
  redirect('/signin');
}

"use server";

import { db } from "@/lib/db";
import { users, ngos, documents, activityLogs, messages, campaigns, projects, events, beneficiaries, teamMembers, boardMembers } from "@/lib/schema";
import { eq, desc, asc, sql } from "drizzle-orm";
import { getServerSession } from "next-auth";
import { authOptions } from "@/lib/auth-options";
import { revalidatePath } from "next/cache";

// --- User Profile Actions ---

export async function updateUserProfile(data: {
  phone?: string;
  location?: string;
  bio?: string;
}) {
  const session = await getServerSession(authOptions);

  if (!session?.user?.email) {
    return { success: false, message: "Unauthorized" };
  }

  try {
    await db.update(users)
      .set({
        phoneNumber: data.phone,
        location: data.location,
        bio: data.bio,
        updatedAt: new Date(),
      })
      .where(eq(users.email, session.user.email));

    revalidatePath("/dashboard/profile");
    return { success: true, message: "Profile updated successfully" };
  } catch (error) {
    console.error("Error updating profile:", error);
    return { success: false, message: "Failed to update profile" };
  }
}

// --- NGO Details Actions ---

export async function saveNGODetails(data: {
  name: string;
  registrationNumber?: string;
  foundedYear?: string;
  establishedYear?: number;
  type?: string;          // New
  panNumber?: string;     // New
  teamSize?: string;
  headquarters?: string;
  description?: string;
  focusAreas?: string[];
  operationalStates?: string[]; // New
  operationalDistricts?: string[]; // New
  vision?: string;        // New
  mission?: string;       // New
  objectives?: string;    // New
  lat?: number;
  lng?: number;
}) {
  const session = await getServerSession(authOptions);

  if (!session?.user?.id) {
    return { success: false, message: "Unauthorized" };
  }

  try {
    const userId = parseInt(session.user.id);

    // Check if NGO exists for this user
    const existingNGO = await db.query.ngos.findFirst({
      where: eq(ngos.ownerId, userId),
    });

    const commonData = {
      name: data.name,
      registrationNumber: data.registrationNumber,
      foundedYear: data.foundedYear, // Legacy
      establishedYear: data.foundedYear ? parseInt(data.foundedYear) : undefined, // Parse
      type: data.type,
      panNumber: data.panNumber,
      teamSize: data.teamSize,
      headquarters: data.headquarters,
      description: data.description,
      focusAreas: data.focusAreas,
      operationalStates: data.operationalStates,
      operationalDistricts: data.operationalDistricts,
      vision: data.vision,
      mission: data.mission,
      objectives: data.objectives,
      lat: data.lat,
      lng: data.lng,
      updatedAt: new Date(),
    };

    if (existingNGO) {
      // Update
      await db.update(ngos)
        .set(commonData)
        .where(eq(ngos.id, existingNGO.id));
    } else {
      // Create
      await db.insert(ngos).values({
        ownerId: userId,
        verified: false,
        paymentClear: false,
        ...commonData,
      });
    }

    revalidatePath("/dashboard/ngo-profile");
    return { success: true, message: "NGO details saved successfully" };
  } catch (error) {
    console.error("Error saving NGO details:", error);
    return { success: false, message: "Failed to save NGO details" };
  }
}



export async function getNGOProfile() {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) return null;

  try {
    const ngo = await db.query.ngos.findFirst({
      where: eq(ngos.ownerId, parseInt(session.user.id)),
    });

    if (!ngo) return null;

    const team = await db.select().from(teamMembers).where(eq(teamMembers.ngoId, ngo.id));
    const board = await db.select().from(boardMembers).where(eq(boardMembers.ngoId, ngo.id));
    const docs = await db.select({ count: sql<number>`count(*)` }).from(documents).where(eq(documents.ngoId, ngo.id));

    return {
      ...ngo,
      teamMembers: team,
      boardMembers: board,
      docCount: docs[0]?.count || 0
    };
  } catch (error) {
    console.error("Error fetching NGO profile:", error);
    return null;
  }
}

export async function getDashboardData() {
  const session = await getServerSession(authOptions);
  if (!session?.user?.id) return null;

  try {
    const userId = parseInt(session.user.id);

    // Fetch NGO
    const ngo = await db.query.ngos.findFirst({
      where: eq(ngos.ownerId, userId),
    });

    if (!ngo) return {
      error: "No NGO profile found",
      userRole: (session.user as any).role
    };

    // Calculate Profile Completion
    let completionScore = 0;

    // 1. Basic Info: Name is mandatory, so if we have a session user, this is effectively true.
    const hasBasicInfo = !!(session.user.name);

    // 2. Contact Info: Require Email AND (Phone OR Location)
    // We need to fetch the user details to check phone/location since they might not be in the session object
    const userDetails = await db.query.users.findFirst({
      where: eq(users.id, userId),
      columns: {
        phoneNumber: true,
        location: true,
      }
    });
    const hasContactInfo = !!(session.user.email && (userDetails?.phoneNumber || userDetails?.location));

    // 3. NGO Details: Require more fields for a "complete" profile
    const hasNgoDetails = !!(
      ngo.name &&
      ngo.description &&
      ngo.headquarters &&
      ngo.foundedYear &&
      ngo.registrationNumber &&
      ngo.teamSize &&
      (ngo.focusAreas && ngo.focusAreas.length > 0)
    );

    const steps = {
      basicInfo: hasBasicInfo,
      contactInfo: hasContactInfo,
      ngoDetails: hasNgoDetails,
      documents: false,
      verification: ngo.verified || false
    };

    if (steps.basicInfo) completionScore += 20;
    if (steps.contactInfo) completionScore += 20;
    if (steps.ngoDetails) completionScore += 20;

    // Fetch Documents
    const docs = await db.select().from(documents).where(eq(documents.ngoId, ngo.id));

    const docStats = {
      total: docs.length,
      verified: docs.filter(d => d.status === 'verified').length,
      pending: docs.filter(d => d.status === 'pending').length,
      missing: docs.filter(d => d.status === 'missing').length
    };

    if (docStats.total > 0) {
      steps.documents = true;
      completionScore += 20;
    }

    if (steps.verification) completionScore += 20;

    // Fetch Recent Activity
    const activities = await db.select().from(activityLogs)
      .where(eq(activityLogs.ngoId, ngo.id))
      .orderBy(desc(activityLogs.createdAt))
      .limit(5);

    // Fetch Messages
    const msgs = await db.select().from(messages)
      .where(eq(messages.receiverId, userId))
      .orderBy(desc(messages.createdAt))
      .limit(3);

    // Count unread messages
    const unreadResult = await db.select({ count: sql<number>`count(*)` })
      .from(messages)
      .where(sql`${messages.receiverId} = ${userId} AND ${messages.isRead} = false`);
    const unreadCount = unreadResult[0]?.count || 0;

    // Fetch Projects
    const projectList = await db.select().from(projects)
      .where(eq(projects.ngoId, ngo.id))
      .orderBy(desc(projects.createdAt))
      .limit(5);

    // Fetch Events (Upcoming)
    const eventList = await db.select().from(events)
      .where(eq(events.ngoId, ngo.id))
      .orderBy(asc(events.date))
      .limit(3);

    // Count Beneficiaries
    const benResult = await db.select({ count: sql<number>`count(*)` })
      .from(beneficiaries)
      .where(eq(beneficiaries.ngoId, ngo.id));
    const totalBeneficiaries = benResult[0]?.count || 0;

    // Calculate Funds (Sum from projects)
    const fundsResult = await db.select({ total: sql<number>`sum(${projects.raisedAmount})` })
      .from(projects)
      .where(eq(projects.ngoId, ngo.id));
    const fundsUtilized = fundsResult[0]?.total || 0;

    // Quick Insights (Derived from actual metrics)
    const insights = {
      engagement: totalBeneficiaries * 3 + (docStats.verified * 50) + (eventList.length * 20),
      profileViews: Math.floor(fundsUtilized / 1000) + (totalBeneficiaries * 2), // Estimation based on activity
      campaigns: await db.select({ count: sql<number>`count(*)` }).from(campaigns).where(eq(campaigns.ngoId, ngo.id)).then(res => res[0].count),
      growth: 15 // This requires historical data which we don't have yet, keeping as placeholder or deriving diff if possible
    };

    const stats = {
      healthScore: Math.min(completionScore + (docStats.verified * 5), 100), // Dynamic score based on completion and docs
      totalBeneficiaries,
      activeProjects: projectList.filter(p => p.status === 'active').length,
      fundsUtilized
    };

    // Prepare dynamic recent documents
    const recentDocuments = await db.select().from(documents)
      .where(eq(documents.ngoId, ngo.id))
      .orderBy(desc(documents.createdAt))
      .limit(3);

    // Mock dynamic achievements based on actual data health
    const achievements = [];
    if (docStats.verified >= 3) {
      achievements.push({ title: "Trust Verified Badge", year: new Date().getFullYear().toString() });
    }
    if (fundsUtilized > 100000) {
      achievements.push({ title: "High Impact Partner", year: "CSR Certified" });
    }
    if (totalBeneficiaries > 500) {
      achievements.push({ title: "Community Champion", year: "500+ Lives Touched" });
    }

    return {
      ngo,
      userName: session.user.name || "Admin",
      completion: {
        score: completionScore,
        steps
      },
      docStats,
      activities,
      messages: msgs,
      unreadCount,
      insights,
      projects: projectList,
      events: eventList,
      recentDocuments,
      achievements,
      stats,
      userRole: (session.user as any).role
    };

  } catch (error) {
    console.error("Error fetching dashboard data:", error);
    return { error: "Failed to fetch dashboard data. Please try again later." };
  }
}

'use server';

import { db } from '@/lib/db';
import { users } from '@/lib/schema';
import { eq, and, gt } from 'drizzle-orm';
import { sendOtpEmail } from '@/lib/mail';
import { redirect } from 'next/navigation';
import bcrypt from 'bcryptjs';
import { z } from 'zod';

const ForgotPasswordSchema = z.object({
  email: z.string().email({ message: 'Please enter a valid email.' }),
});

const ResetPasswordSchema = z.object({
  email: z.string().email(),
  otp: z.string().min(6, 'OTP must be 6 digits'),
  password: z.string().min(6, 'Password must be at least 6 characters'),
  confirmPassword: z.string(),
}).refine((data) => data.password === data.confirmPassword, {
  message: "Passwords don't match",
  path: ["confirmPassword"],
});

export async function requestOtp(prevState: any, formData: FormData) {
  const validatedFields = ForgotPasswordSchema.safeParse({
    email: formData.get('email'),
  });

  if (!validatedFields.success) {
    return {
      errors: validatedFields.error.flatten().fieldErrors,
    };
  }

  const { email } = validatedFields.data;

  // Check if user exists
  const existingUser = await db.select().from(users).where(eq(users.email, email));
  if (existingUser.length === 0) {
    // Return success even if user doesn't exist to prevent enumeration
    return {
      message: 'If an account exists with this email, an OTP has been sent.',
    };
  }

  // Generate OTP
  const otp = Math.floor(100000 + Math.random() * 900000).toString();
  const expiresAt = new Date(Date.now() + 10 * 60 * 1000); // 10 minutes from now

  // Update User
  await db.update(users)
    .set({ otpCode: otp, otpExpiresAt: expiresAt })
    .where(eq(users.email, email));

  // Send Email
  await sendOtpEmail(email, otp);

  // Redirect to verify page with email as query param (or handle in state)
  // Using redirect here might reset the form state, but we want to move to next step.
  redirect(`/verify-otp?email=${encodeURIComponent(email)}`);
}

export async function resetPassword(prevState: any, formData: FormData) {
  const email = formData.get('email') as string; // Hidden field
  
  const validatedFields = ResetPasswordSchema.safeParse({
    email: email,
    otp: formData.get('otp'),
    password: formData.get('password'),
    confirmPassword: formData.get('confirmPassword'),
  });

  if (!validatedFields.success) {
    return {
      errors: validatedFields.error.flatten().fieldErrors,
    };
  }

  const { otp, password } = validatedFields.data;

  // Find user with matching Email, OTP, and Not Expired
  const [user] = await db.select().from(users).where(
    and(
      eq(users.email, email),
      eq(users.otpCode, otp),
      gt(users.otpExpiresAt, new Date())
    )
  );

  if (!user) {
    return {
      message: 'Invalid or expired OTP.',
    };
  }

  // Hash new password
  const hashedPassword = await bcrypt.hash(password, 10);

  // Update User
  await db.update(users)
    .set({ 
      password: hashedPassword, 
      otpCode: null, 
      otpExpiresAt: null 
    })
    .where(eq(users.id, user.id));

  redirect('/signin?reset=success');
}

"use server";

