                    >
                        Cancel
                    </button>
                    <button 
                        onClick={handleDelete}
                        disabled={loadingId === deleteModal.id}
                        className="px-4 h-10 text-sm font-semibold text-white bg-red-500 rounded-xl hover:bg-red-600 transition-colors btn-press disabled:opacity-50 shadow-sm flex items-center gap-2"
                    >
                        <Trash2 className="w-4 h-4" />
                        {loadingId === deleteModal.id ? "Deleting…" : "Delete NGO"}
                    </button>
                </div>
            </div>
        </div>
    )}
    </>
  );
}

"use client";

import { motion, Variants } from "framer-motion";

interface TypewriterTextProps {
  text: string;
  className?: string;
  delay?: number;
}

export default function TypewriterText({ text, className = "", delay = 0 }: TypewriterTextProps) {
  // Split text into characters
  const characters = Array.from(text);

  const container: Variants = {
    hidden: { opacity: 0 },
    visible: (i = 1) => ({
      opacity: 1,
      transition: { staggerChildren: 0.03, delayChildren: delay },
    }),
  };

  const child: Variants = {
    visible: {
      opacity: 1,
      y: 0,
      transition: {
        type: "spring",
        damping: 12,
        stiffness: 100,
      },
    },
    hidden: {
      opacity: 0,
      y: 20,
      transition: {
        type: "spring",
        damping: 12,
        stiffness: 100,
      },
    },
  };

  return (
    <motion.h1
      style={{ display: "flex", flexWrap: "wrap" }} // Ensure wrapping handled correctly
      variants={container}
      initial="hidden"
      whileInView="visible"
      viewport={{ once: true }}
      className={className}
    >
      {characters.map((char, index) => (
        <motion.span variants={child} key={`char-${index}`} className={char === " " ? "mr-2" : ""}>
          {char}
        </motion.span>
      ))}
    </motion.h1>
  );
}

