            </tr>
          </thead>
          <tbody className="divide-y divide-gray-100">
            {filteredData.map((item, index) => (
              <tr key={index} className="hover:bg-gray-50 transition-colors">
                <td className="px-6 py-4 whitespace-nowrap text-sm font-medium text-gray-900">{item.name}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{item.age} / {item.gender}</td>
                <td className="px-6 py-4 whitespace-nowrap">
                   <CategoryBadge category={item.category} />
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{item.project || '-'}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">{item.location}</td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-500">
                  {new Date(item.registeredAt).toLocaleDateString()}
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-right">
                  <div className="flex justify-end gap-2">
                    <button 
                        onClick={() => setSelectedBeneficiary(item)}
                        className="p-1 text-blue-600 hover:bg-blue-50 rounded"
                    >
                      <Eye className="w-4 h-4" />
                    </button>
                    <button 
                        onClick={() => handleDelete(item.id)} 
                        className="p-1 text-red-600 hover:bg-red-50 rounded"
                    >
                       <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
            {filteredData.length === 0 && (
              <tr>
                <td colSpan={7} className="px-6 py-8 text-center text-gray-500">
                  No beneficiaries found.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Add Beneficiary Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
           <div className="bg-white rounded-2xl p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
              <div className="flex justify-between items-center mb-6">
                 <h2 className="text-xl font-bold text-gray-900">Add New Beneficiary</h2>
                 <button onClick={() => setIsModalOpen(false)} className="text-gray-500 hover:text-gray-700">
                    <Plus className="w-6 h-6 rotate-45" />
                 </button>
              </div>
              
              <form onSubmit={handleSubmit} className="space-y-4">
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                       <label className="block text-sm font-medium text-gray-700 mb-1">Full Name *</label>
                       <input required name="name" value={formData.name} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none" />
                    </div>
                    <div>
                       <label className="block text-sm font-medium text-gray-700 mb-1">Age *</label>
                       <input required type="number" name="age" value={formData.age} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none" />
                    </div>
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                       <label className="block text-sm font-medium text-gray-700 mb-1">Gender</label>
                       <select name="gender" value={formData.gender} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none">
                          <option value="">Select Gender</option>
                          <option value="Male">Male</option>
                          <option value="Female">Female</option>
                          <option value="Other">Other</option>
                       </select>
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">Category</label>
                       <select name="category" value={formData.category} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none">
                          <option value="">Select Category</option>
                          <option value="Child">Child</option>
                          <option value="Women">Women</option>
                          <option value="Elderly">Elderly</option>
                          <option value="Other">Individual</option>
                       </select>
                    </div>
                 </div>

                 <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Link to Project</label>
                    <select name="projectId" value={formData.projectId} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none">
                       <option value="">Select a Project</option>
                       {projects.map(p => (
                          <option key={p.id} value={p.id}>{p.title}</option>
                       ))}
                    </select>
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                       <label className="block text-sm font-medium text-gray-700 mb-1">Location</label>
                       <input name="location" value={formData.location} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none" />
                    </div>
                    <div>
                       <label className="block text-sm font-medium text-gray-700 mb-1">Phone</label>
                       <input name="phone" value={formData.phone} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none" />
                    </div>
                 </div>

                 <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Notes</label>
                    <textarea name="notes" value={formData.notes} onChange={handleInputChange} rows={3} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none"></textarea>
                 </div>

                 <div className="flex gap-3 pt-4 border-t">
                    <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 px-4 py-2 border rounded-lg text-gray-700 hover:bg-gray-50">Cancel</button>
                    <button type="submit" disabled={isSubmitting} className="flex-1 px-4 py-2 bg-[#0EA5E9] text-white rounded-lg hover:bg-[#0284c7] disabled:opacity-50">
                       {isSubmitting ? "Adding..." : "Add Beneficiary"}
                    </button>
                 </div>
              </form>
           </div>
        </div>
      )}

      {/* View Beneficiary Modal */}
      {selectedBeneficiary && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
           <div className="bg-white rounded-2xl p-6 w-full max-w-lg relative">
              <button 
                  onClick={() => setSelectedBeneficiary(null)} 
                  className="absolute top-4 right-4 p-2 bg-gray-100 rounded-full hover:bg-gray-200"
              >
                  <X className="w-5 h-5 text-gray-500" />
              </button>

              <h2 className="text-xl font-bold text-gray-900 mb-4">Beneficiary Details</h2>
              <div className="space-y-4">
                  <div className="flex justify-between border-b pb-2">
                      <span className="text-gray-500">Name</span>
                      <span className="font-semibold">{selectedBeneficiary.name}</span>
                  </div>
                  <div className="flex justify-between border-b pb-2">
                       <span className="text-gray-500">Age / Gender</span>
                       <span className="font-semibold">{selectedBeneficiary.age} / {selectedBeneficiary.gender}</span>
                  </div>
                  <div className="flex justify-between border-b pb-2">
                       <span className="text-gray-500">Category</span>
                       <CategoryBadge category={selectedBeneficiary.category} />
                  </div>
                   <div className="flex justify-between border-b pb-2">
                       <span className="text-gray-500">Project</span>
                       <span className="font-semibold">{selectedBeneficiary.project || "N/A"}</span>
                  </div>
                   <div className="flex justify-between border-b pb-2">
                       <span className="text-gray-500">Location</span>
                       <span className="font-semibold">{selectedBeneficiary.location || "N/A"}</span>
                  </div>
                   <div className="flex justify-between border-b pb-2">
                       <span className="text-gray-500">Phone</span>
                       <span className="font-semibold">{selectedBeneficiary.phone || "N/A"}</span>
                  </div>
                   <div className="flex justify-between pb-2">
                       <span className="text-gray-500">Registered</span>
                       <span className="font-semibold">{new Date(selectedBeneficiary.registeredAt).toLocaleDateString()}</span>
                  </div>
              </div>

               <div className="mt-6 flex justify-end">
                   <button onClick={() => setSelectedBeneficiary(null)} className="px-4 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200">
                       Close
                   </button>
               </div>
           </div>
        </div>
      )}

      {/* Bulk Upload Modal */}
      {isBulkUploadOpen && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
              <div className="bg-white rounded-2xl p-6 w-full max-w-md text-center">
                  <div className="flex justify-between items-center mb-6">
                      <h2 className="text-xl font-bold text-gray-900">Bulk Upload</h2>
                      <button onClick={() => setIsBulkUploadOpen(false)} className="text-gray-500 hover:text-gray-700">
                          <Plus className="w-6 h-6 rotate-45" />
                      </button>
                  </div>
                  
                  <div className="border-2 border-dashed border-gray-200 rounded-xl p-8 mb-6 flex flex-col items-center justify-center">
                      <Upload className="w-12 h-12 text-gray-400 mb-4" />
                      <p className="text-gray-600 mb-4">Upload an Excel file with beneficiary data</p>
                      <button className="px-6 py-2 bg-[#0EA5E9] text-white rounded-lg hover:bg-[#0284c7]">
                          Choose File
                      </button>
                      <p className="text-xs text-gray-400 mt-4">Supported format: .xlsx, .xls</p>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
}

function StatsCard({ title, value, icon: Icon, color }: any) {
  return (
    <div className={`${color} text-white rounded-xl p-6 relative overflow-hidden`}>
      <div className="relative z-10">
        <p className="text-blue-100 text-sm font-medium mb-2">{title}</p>
        <h3 className="text-4xl font-bold">{value}</h3>
      </div>
      <Icon className="absolute right-4 bottom-4 w-20 h-20 text-white opacity-10" />
    </div>
  );
}

function CategoryBadge({ category }: { category: string }) {
  // Using uniform blue as requested/observed in design
  return (
    <span className="px-3 py-1 bg-blue-100 text-[#0EA5E9] text-xs font-medium rounded-full">
      {category}
    </span>
  );
}

"use client";

import { useState } from "react";
import { 
  Plus, 
  Search, 
  Handshake, 
  CheckCircle2, 
  Clock, 
  TrendingUp,
  Building2,
  Mail, 
  User, 
  MapPin, 
  Star,
  Eye,
  MessageSquare,
  Trash2,
  X
} from "lucide-react";


import { createPartner, deletePartner } from "@/actions/ngo-features";
import { useRouter } from "next/navigation";

export default function CollaborationClient({ initialData, initialStats }: { initialData: any[], initialStats: any }) {
  const router = useRouter();
  const [data, setData] = useState(initialData);

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedPartner, setSelectedPartner] = useState<any>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
      organizationName: "",
      type: "NGO",
      contactPerson: "",
      email: "",
      phone: "",
      location: "",
      description: ""
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
      setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      setIsSubmitting(true);
      try {
          const result = await createPartner(formData);
          if (result.success) {
              setIsModalOpen(false);
              setFormData({ 
                  organizationName: "",
                  type: "NGO",
                  contactPerson: "",
                  email: "",
                  phone: "",
                  location: "",
                  description: ""
              });
              router.refresh();
              alert("Partner added successfully!");
          } else {
              alert("Failed: " + result.error);
          }
      } catch (err) {
          console.error(err);
      } finally {
          setIsSubmitting(false);
      }
  };

  const handleDelete = async (id: number) => {
      if(!confirm("Are you sure you want to delete this partner?")) return;
      try {
          const result = await deletePartner(id);
          if (result.success) {
              router.refresh();
              alert("Partner deleted successfully");
          } else {
              alert("Failed to delete: " + result.error);
          }
      } catch (err) {
          console.error(err);
          alert("An error occurred");
      }
  };


  return (
    <div className="p-8 space-y-8 relative">
      {/* Header */}
      <div className="flex justify-between items-start">
         <div>
          <h1 className="text-2xl font-bold text-gray-900">Collaboration & Partnerships</h1>
          <p className="text-gray-500">Build strategic alliances for greater impact</p>
        </div>
        <button 
           onClick={() => setIsModalOpen(true)}
           className="flex items-center gap-2 px-4 py-2 text-white bg-[#0EA5E9] rounded-lg hover:bg-[#0284c7]"
        >
          <Plus className="w-4 h-4" />
          Add Partner
        </button>
      </div>

       {/* Stats Cards */}
       <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <StatsCard 
          title="Total Partners" 
          value={initialStats.total} 
          icon={Handshake}
          color="bg-[#0EA5E9]" 
        />
        <StatsCard 
          title="Active Partnerships" 
          value={initialStats.active} 
          icon={CheckCircle2}
          color="bg-[#0284c7]"
        />
        <StatsCard 
          title="Pending Approval" 
          value={initialStats.pending} 
          icon={Clock}
          color="bg-[#0369a1]"
        />
        <StatsCard 
          title="Joint Projects" 
          value={initialStats.jointProjs} 
          icon={TrendingUp}
          color="bg-[#075985]"
        />
      </div>

       {/* Filters */}
       <div className="flex gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5" />
          <input
            type="text"
            placeholder="Search partners..."
            className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#0EA5E9]"
          />
        </div>
        <select 
          className="px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#0EA5E9] bg-white text-gray-600 min-w-[150px]"
        >
          <option value="All">All Status</option>
          <option value="Active">Active</option>
          <option value="Pending">Pending</option>
        </select>
      </div>

       {/* Collaborative Partners Grid */}
       <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
           {data.map((partner, index) => (
               <PartnerCard 
                  key={partner.id} 
                  partner={partner} 
                  index={index} 
                  onDelete={() => handleDelete(partner.id)}
                  onView={() => setSelectedPartner(partner)}
               />
           ))}
           {data.length === 0 && (
               <div className="col-span-full py-12 text-center text-gray-500">
                   No partners found.
               </div>
           )}
       </div>

       {/* Add Partner Modal */}
       {isModalOpen && (
           <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50">
               <div className="bg-white rounded-2xl p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
                   <div className="flex justify-between items-center mb-6">
                       <h2 className="text-xl font-bold text-gray-900">Add New Partner</h2>
                       <button onClick={() => setIsModalOpen(false)} className="text-gray-500 hover:text-gray-700">
                           <Plus className="w-6 h-6 rotate-45" />
                       </button>
                   </div>
                   <form onSubmit={handleSubmit} className="space-y-4">
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                           <div>
                               <label className="block text-sm font-medium text-gray-700 mb-1">Organization Name *</label>
                               <input required name="organizationName" value={formData.organizationName} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none" placeholder="Enter organization name" />
                           </div>
                           <div>
                               <label className="block text-sm font-medium text-gray-700 mb-1">Type *</label>
                               <select name="type" value={formData.type} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none">
                                   <option value="NGO">NGO</option>
                                   <option value="Corporate">Corporate</option>
                                   <option value="Government">Government</option>
                                   <option value="Educational">Educational</option>
                               </select>
                           </div>
                       </div>

                       <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                           <div>
                               <label className="block text-sm font-medium text-gray-700 mb-1">Contact Person</label>
                               <input name="contactPerson" value={formData.contactPerson} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none" placeholder="Contact person name" />
                           </div>
                           <div>
                               <label className="block text-sm font-medium text-gray-700 mb-1">Email *</label>
                               <input required type="email" name="email" value={formData.email} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none" placeholder="email@example.com" />
                           </div>
                       </div>

                       <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                           <div>
                               <label className="block text-sm font-medium text-gray-700 mb-1">Phone</label>
                               <input name="phone" value={formData.phone} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none" placeholder="+91 XXXXX XXXXX" />
                           </div>
                           <div>
                               <label className="block text-sm font-medium text-gray-700 mb-1">Location</label>
                               <input name="location" value={formData.location} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none" placeholder="City" />
                           </div>
                       </div>

                       <div>
                           <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                           <textarea name="description" value={formData.description} onChange={handleInputChange} rows={3} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none" placeholder="Brief description of the partnership"></textarea>
                       </div>

                       <div className="flex gap-3 pt-4 border-t">
                           <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 px-4 py-2 border rounded-lg text-gray-700 hover:bg-gray-50">Cancel</button>
                           <button type="submit" disabled={isSubmitting} className="flex-1 px-4 py-2 bg-[#0EA5E9] text-white rounded-lg hover:bg-[#0284c7] disabled:opacity-50">
                               {isSubmitting ? "Adding..." : "Add Partner"}
                           </button>
                       </div>
                   </form>
               </div>
           </div>
       )}

       {/* View Partner Modal */}
       {selectedPartner && (
            <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center z-50">
               <div className="bg-white rounded-2xl p-6 w-full max-w-lg relative">
                   <button 
                       onClick={() => setSelectedPartner(null)} 
                       className="absolute top-4 right-4 p-2 bg-gray-100 rounded-full hover:bg-gray-200 transition-colors"
                   >
                       <X className="w-5 h-5 text-gray-500" />
                   </button>
                   
                   <div className="mb-6 flex items-center gap-4">
                        <div className="w-16 h-16 bg-[#0f4c81] rounded-xl flex items-center justify-center text-white font-bold">
                             <Building2 className="w-8 h-8" />
                        </div>
                        <div>
                             <h2 className="text-xl font-bold text-gray-900">{selectedPartner.organizationName}</h2>
                             <span className="px-2 py-1 bg-blue-50 text-blue-600 rounded text-xs font-semibold">{selectedPartner.type} Partner</span>
                        </div>
                   </div>

                   <p className="text-gray-600 mb-6">{selectedPartner.description || "No description provided."}</p>

                   <div className="space-y-4">
                       <div className="flex items-center gap-3">
                           <User className="w-5 h-5 text-gray-400" />
                           <div>
                               <p className="text-xs text-gray-500">Contact Person</p>
                               <p className="font-medium text-gray-900">{selectedPartner.contactPerson}</p>
                           </div>
                       </div>
                       <div className="flex items-center gap-3">
                           <Mail className="w-5 h-5 text-gray-400" />
                           <div>
                               <p className="text-xs text-gray-500">Email</p>
                               <p className="font-medium text-gray-900">{selectedPartner.email}</p>
                           </div>
                       </div>
                       <div className="flex items-center gap-3">
                           <MapPin className="w-5 h-5 text-gray-400" />
                           <div>
                               <p className="text-xs text-gray-500">Location</p>
                               <p className="font-medium text-gray-900">{selectedPartner.location}</p>
                           </div>
                       </div>
                   </div>

                   <div className="flex justify-end pt-6 mt-6 border-t border-gray-100">
                       <button onClick={() => setSelectedPartner(null)} className="px-6 py-2 bg-gray-100 text-gray-700 rounded-lg hover:bg-gray-200">
                           Close
                       </button>
                   </div>
               </div>
           </div>
       )}
    </div>
  );
}

function StatsCard({ title, value, icon: Icon, color }: any) {
  return (
    <div className={`${color} text-white rounded-xl p-6 relative overflow-hidden flex items-center justify-between`}>
      <div className="relative z-10">
         <Icon className="w-8 h-8 mb-3 opacity-80" />
         <p className="text-blue-100 text-sm font-medium mb-1">{title}</p>
      </div>
       <div className="bg-white/20 w-12 h-12 rounded-lg backdrop-blur-sm flex items-center justify-center">
         <span className="text-2xl font-bold">{value}</span>
      </div>
    </div>
  );
}

function PartnerCard({ partner, index, onDelete, onView }: { partner: any, index: number, onDelete: () => void, onView: () => void }) {
    // Determine status style
    const isPending = partner.status === 'submitted' || partner.status === 'pending';
    const statusBg = isPending ? 'bg-orange-100 text-orange-700' : 'bg-green-100 text-green-700';
    const statusText = isPending ? 'Pending' : 'Active';
    
    const sinceDate = new Date(partner.createdAt).toLocaleDateString(undefined, { month: 'short', year: 'numeric' });
    const contactName = partner.contactPerson || "N/A"; 
    const contactEmail = partner.email || "N/A"; 
    
    return (
        <div className="bg-white border border-gray-100 rounded-xl p-6 hover:shadow-md transition-shadow">
             <div className="flex justify-between items-start mb-4">
                 <div className="flex items-center gap-4">
                     <div className="w-12 h-12 bg-[#0f4c81] rounded-lg flex items-center justify-center text-white font-bold">
                         <Building2 className="w-6 h-6" />
                     </div>
                     <div>
                         <h3 className="font-bold text-gray-900">{partner.organizationName}</h3>
                         <p className="text-xs text-gray-500">{partner.type || "Partner"}</p>
                     </div>
                 </div>
                 <div className="text-right">
                      <span className={`px-2 py-1 rounded text-xs font-semibold ${statusBg} block mb-1`}>
                          {statusText}
                      </span>
                 </div>
             </div>

             <p className="text-sm text-gray-600 mb-4 h-10 overflow-hidden">{partner.description || "Strategic partnership for social impact."}</p>

             <div className="space-y-2 mb-6">
                 <div className="flex items-center gap-2 text-sm text-gray-500">
                     <User className="w-4 h-4" />
                     <span>{contactName}</span>
                 </div>
                  <div className="flex items-center gap-2 text-sm text-gray-500">
                     <Mail className="w-4 h-4" />
                     <span>{contactEmail}</span>
                 </div>
                  <div className="flex items-center gap-2 text-sm text-gray-500">
                     <MapPin className="w-4 h-4" />
                     <span>{partner.location || "Location not specified"}</span>
                 </div>
             </div>

             <div className="flex justify-between items-center py-4 border-t border-gray-50 mb-4 px-4 bg-gray-50 rounded-lg">
                 <div className="text-center w-full">
                     <p className="font-bold text-gray-900">{sinceDate}</p>
                     <p className="text-xs text-gray-500">Partner Since</p>
                 </div>
             </div>

             <div className="flex gap-2">
                 <button 
                    onClick={onView}
                    className="flex-1 py-2 bg-blue-50 text-blue-600 text-xs font-semibold rounded-lg flex items-center justify-center gap-2 hover:bg-blue-100"
                 >
                     <Eye className="w-3.5 h-3.5" /> View
                 </button>
                  <button className="flex-1 py-2 bg-gray-50 text-gray-900 text-xs font-semibold rounded-lg flex items-center justify-center gap-2 hover:bg-gray-100">
                     <MessageSquare className="w-3.5 h-3.5" /> Contact
                 </button>
                 <button 
                    onClick={onDelete}
                    className="p-2 bg-red-50 text-red-600 rounded-lg hover:bg-red-100"
                 >
                     <Trash2 className="w-3.5 h-3.5" />
                 </button>
             </div>
        </div>
    );
}

"use client";

import Link from "next/link";
import { 
  Plus, 
  Users, 
  UploadCloud, 
  FileText, 
  MoreHorizontal, 
  Calendar, 
  ChevronRight, 
  Trophy,
  CheckCircle2,
  Clock,
  AlertCircle,
  TrendingUp,
  Activity,
  Layers,
  IndianRupee,
  ChevronDown
} from "lucide-react";
import Image from "next/image";
import { useState } from "react";

interface DashboardClientProps {
  data: {
    ngo: any;
    userName: string;
    completion: {
      score: number;
      steps: any;
    };
    docStats: {
      total: number;
      verified: number;
      pending: number;
      missing: number;
    };
    stats: {
      healthScore: number;
      totalBeneficiaries: number;
      activeProjects: number;
      fundsUtilized: number;
    };
    projects: any[];
    events: any[];
    activities: any[];     // Keep for legacy if needed, or remove
    messages: any[];       // Keep for header badges if needed
    unreadCount: number;
  };
}

export default function DashboardClient({ data }: DashboardClientProps) {
  const { ngo, userName, docStats, stats, projects, events } = data;

  const formatCurrency = (amount: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      maximumFractionDigits: 0
    }).format(amount);
  };

  const formatDate = (dateString: string | Date) => {
    return new Date(dateString).toLocaleDateString('en-GB', {
      day: 'numeric',
      month: 'short',
      year: 'numeric'
    });
  };

  const handleGenerateReport = () => {
      const headers = ["Metric", "Value"];
      const csvData = [
          ["Health Score", stats.healthScore],
          ["Total Beneficiaries", stats.totalBeneficiaries],
          ["Active Projects", stats.activeProjects],
          ["Funds Utilized", stats.fundsUtilized]
      ].map(row => row.join(","));

      const csvString = [headers.join(","), ...csvData].join("\n");
      const blob = new Blob([csvString], { type: 'text/csv;charset=utf-8;' });
      const link = document.createElement("a");
      const url = URL.createObjectURL(blob);
      link.setAttribute("href", url);
      link.setAttribute("download", `ngo_report_${new Date().toISOString().split('T')[0]}.csv`);
      link.style.visibility = 'hidden';
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
  };

  return (
    <div className="space-y-8">
      {/* Header Section */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">User Dashboard</h1>
          <p className="text-gray-500">Your NGO overview at a glance</p>
        </div>
      </div>

      {/* Verification Status Banner */}
      {(!ngo.verified || docStats.pending > 0 || docStats.missing > 0) && (
        <div className="relative overflow-hidden bg-white border border-gray-100 rounded-3xl p-6 shadow-sm">
          {/* Decorative background element */}
          <div className="absolute top-0 right-0 w-64 h-64 bg-blue-50/50 rounded-full blur-3xl -mr-32 -mt-32"></div>
          
          <div className="relative z-10 flex flex-col md:flex-row items-start md:items-center justify-between gap-6">
            <div className="flex items-start gap-4">
              <div className={`p-3 rounded-2xl ${ngo.verified ? 'bg-green-100 text-green-600' : 'bg-orange-100 text-orange-600'}`}>
                {ngo.verified ? <CheckCircle2 className="w-6 h-6" /> : <Clock className="w-6 h-6" />}
              </div>
              <div>
                <h3 className="text-lg font-bold text-gray-900">
                  {ngo.verified ? "Profile Verified" : "Verification In Progress"} 
                  <span className="ml-2 text-xs font-medium px-2 py-0.5 rounded-full bg-gray-100 text-gray-500 uppercase tracking-wider">NGO ID: {ngo.registrationNumber || 'Pending'}</span>
                </h3>
                <p className="text-gray-500 mt-1 max-w-xl">
                  {ngo.verified 
                    ? "Great! Your NGO is fully verified. You can now access all fundraising and CSR features."
                    : `You have ${docStats.pending} documents under review and ${docStats.missing} documents missing. Complete your profile to unlock all features.`}
                </p>
                <div className="flex items-center gap-4 mt-4 text-sm font-medium">
                  <div className="flex items-center gap-1.5 text-green-600">
                    <CheckCircle2 className="w-4 h-4" /> {docStats.verified} Verified
                  </div>
                  <div className="flex items-center gap-1.5 text-orange-500">
                    <Clock className="w-4 h-4" /> {docStats.pending} Pending
                  </div>
                  <div className="flex items-center gap-1.5 text-red-500">
                    <AlertCircle className="w-4 h-4" /> {docStats.missing} Missing
                  </div>
                </div>
              </div>
            </div>
            
            {!ngo.verified && (
              <Link href="/onboarding">
                <button className="whitespace-nowrap px-6 py-3 bg-blue-600 text-white font-bold rounded-xl hover:bg-blue-700 hover:shadow-lg hover:shadow-blue-200 transition-all flex items-center gap-2">
                  Complete Verification <ChevronRight className="w-4 h-4" />
                </button>
              </Link>
            )}
          </div>
        </div>
      )}

      {/* Stats Cards Row */}
      <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-4 gap-6">
        
        {/* Card 1: Health Score (Blue) */}
        <div className="bg-[#3b82f6] rounded-2xl p-6 text-white relative overflow-hidden">
           <div className="flex items-start justify-between relative z-10">
              <div>
                 <p className="text-blue-100 text-sm font-medium flex items-center gap-2">
                    <Activity className="w-4 h-4" /> NGO Health Score
                 </p>
                 <h2 className="text-4xl font-bold mt-2">{stats.healthScore}</h2>
                 <p className="text-blue-100 text-sm mt-1">Good</p>
              </div>
           </div>
           {/* Decor/Chart placeholder */}
           <div className="absolute right-0 bottom-0 opacity-10">
              <Activity className="w-32 h-32 transform translate-x-8 translate-y-8" />
           </div>
        </div>

        {/* Card 2: Beneficiaries (Tealish) */}
        <div className="bg-[#0ea5e9] rounded-2xl p-6 text-white relative overflow-hidden">
           <div className="flex items-start justify-between relative z-10">
              <div>
                 <p className="text-sky-100 text-sm font-medium flex items-center gap-2">
                    <Users className="w-4 h-4" /> Total Beneficiaries
                 </p>
                 <h2 className="text-4xl font-bold mt-2">{stats.totalBeneficiaries.toLocaleString()}</h2>
              </div>
           </div>
           <div className="absolute right-0 bottom-0 opacity-10">
              <Users className="w-32 h-32 transform translate-x-8 translate-y-8" />
           </div>
        </div>

        {/* Card 3: Active Projects (Darker Blue) */}
        <div className="bg-[#0284c7] rounded-2xl p-6 text-white relative overflow-hidden">
           <div className="flex items-start justify-between relative z-10">
              <div>
                 <p className="text-sky-100 text-sm font-medium flex items-center gap-2">
                    <CheckCircle2 className="w-4 h-4" /> Active Projects
                 </p>
                 <h2 className="text-4xl font-bold mt-2">{stats.activeProjects}</h2>
              </div>
           </div>
           <div className="absolute right-0 bottom-0 opacity-10">
              <Layers className="w-32 h-32 transform translate-x-8 translate-y-8" />
           </div>
        </div>

        {/* Card 4: Funds Utilized (Darkest Blue) */}
        <div className="bg-[#0f172a] rounded-2xl p-6 text-white relative overflow-hidden">
           <div className="flex items-start justify-between relative z-10">
              <div>
                 <p className="text-slate-300 text-sm font-medium flex items-center gap-2">
                    <IndianRupee className="w-4 h-4" /> Funds Utilized
                 </p>
                 <h2 className="text-3xl font-bold mt-2">{formatCurrency(stats.fundsUtilized)}</h2>
              </div>
           </div>
           {/* Simple chart line SVG */}
           <svg className="absolute bottom-0 left-0 w-full h-16 text-slate-700 opacity-50" viewBox="0 0 100 20" preserveAspectRatio="none">
              <path d="M0,20 L0,10 Q25,18 50,5 T100,10 L100,20 Z" fill="currentColor" />
           </svg>
        </div>
      </div>

      {/* Action Buttons Row */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
         <Link href="/dashboard/projects/new" className="flex items-center justify-center gap-2 bg-white border border-gray-200 p-4 rounded-xl text-blue-600 font-medium hover:bg-blue-50 transition-colors shadow-sm">
            <Plus className="w-5 h-5" /> Add New Project
         </Link>
         <Link href="/dashboard/beneficiaries" className="flex items-center justify-center gap-2 bg-white border border-gray-200 p-4 rounded-xl text-gray-700 font-medium hover:bg-gray-50 transition-colors shadow-sm">
            <Users className="w-5 h-5 text-gray-400" /> Register Beneficiaries
         </Link>
         <Link href="/dashboard/documents" className="flex items-center justify-center gap-2 bg-white border border-gray-200 p-4 rounded-xl text-gray-700 font-medium hover:bg-gray-50 transition-colors shadow-sm">
            <UploadCloud className="w-5 h-5 text-gray-400" /> Upload Documents
         </Link>
         <button onClick={handleGenerateReport} className="flex items-center justify-center gap-2 bg-white border border-gray-200 p-4 rounded-xl text-gray-700 font-medium hover:bg-gray-50 transition-colors shadow-sm btn-press">
            <FileText className="w-5 h-5 text-gray-400" /> Generate Report
         </button>
      </div>

      {/* Main Content Grid */}
      <div className="grid grid-cols-1 xl:grid-cols-3 gap-8">
         
         {/* Left Column (2/3) */}
         <div className="xl:col-span-2 space-y-8">
            
            {/* Ongoing Projects */}
            <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
               <div className="flex justify-between items-center mb-6">
                  <h3 className="text-lg font-bold text-gray-900">Ongoing Projects</h3>
                  <Link href="/dashboard/projects" className="text-sm text-blue-600 font-medium flex items-center gap-1">
                     Manage Projects <ChevronDown className="w-4 h-4" />
                  </Link>
               </div>
               
               <div className="space-y-4">
                  {projects.length > 0 ? projects.map((project, i) => (
                     <div key={i} className="flex items-center justify-between p-4 bg-gray-50 rounded-xl hover:bg-gray-100 transition-colors">
                        <div className="flex items-center gap-4">
                           <div className="w-10 h-10 bg-white rounded-lg flex items-center justify-center shadow-sm text-lg">
                              {/* Simple icon or first letter */}
                              {project.title.charAt(0)}
                           </div>
                           <h4 className="font-semibold text-gray-900">{project.title}</h4>
                        </div>
                        <div className="flex items-center gap-4">
                           <span className={`px-3 py-1 text-xs font-medium rounded-full ${
                              project.status === 'active' ? 'bg-blue-100 text-blue-700' : 
                              project.status === 'completed' ? 'bg-green-100 text-green-700' : 'bg-yellow-100 text-yellow-700'
                           }`}>
                              {project.status === 'active' ? 'In Progress' : project.status}
                           </span>
                           <ChevronRight className="w-5 h-5 text-gray-400" />
                        </div>
                     </div>
                  )) : (
                     <div className="text-center py-8 text-gray-500">No active projects yet.</div>
                  )}
               </div>
            </div>

            {/* Beneficiary Overview */}
            <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
               <h3 className="text-lg font-bold text-gray-900 mb-6">Beneficiary Overview</h3>
               <div className="flex flex-col md:flex-row gap-8">
                  <div className="space-y-4 flex-1">
                     <div className="flex items-center gap-3 text-gray-700">
                        <Users className="w-5 h-5 text-blue-500" />
                        <span className="font-semibold">{stats.totalBeneficiaries.toLocaleString()}</span> Total Registered
                     </div>
                     <div className="flex items-center gap-3 text-gray-700">
                        <span className="w-2 h-2 rounded-full bg-yellow-400 ml-1.5 mr-1.5"></span>
                        <span className="font-semibold">{Math.floor(stats.totalBeneficiaries * 0.45).toLocaleString()}</span> Children
                     </div>
                     <div className="flex items-center gap-3 text-gray-700">
                         <span className="w-2 h-2 rounded-full bg-orange-400 ml-1.5 mr-1.5"></span>
                        <span className="font-semibold">{Math.floor(stats.totalBeneficiaries * 0.35).toLocaleString()}</span> Women
                     </div>
                     <div className="flex items-center gap-3 text-gray-700">
                         <span className="w-2 h-2 rounded-full bg-green-400 ml-1.5 mr-1.5"></span>
                        <span className="font-semibold">{Math.floor(stats.totalBeneficiaries * 0.20).toLocaleString()}</span> Elderly
                     </div>
                     <Link href="/dashboard/beneficiaries" className="text-blue-600 font-medium text-sm mt-4 inline-block">
                        View All Beneficiaries
                     </Link>
                  </div>
                  <div className="w-full md:w-48 h-32 md:h-auto bg-gray-200 rounded-xl overflow-hidden relative">
                     <Image 
                        src="https://images.unsplash.com/photo-1488521787991-ed7bbaae773c?q=80&w=1000&auto=format&fit=crop" 
                        alt="Beneficiaries" 
                        fill
                        className="object-cover"
                     />
                  </div>
               </div>
            </div>

            {/* Impact Summary */}
            <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
               <div className="flex justify-between items-center mb-6">
                  <h3 className="text-lg font-bold text-gray-900">Latest Impact Summary</h3>
                  <Link href="/dashboard/projects" className="text-sm text-blue-600 font-medium flex items-center gap-1 hover:underline">
                     View All Projects <ChevronRight className="w-4 h-4" />
                  </Link>
               </div>
               <div className="space-y-4">
                  {projects.length > 0 ? projects.slice(0, 2).map((project, idx) => (
                      <div key={idx} className={`${idx % 2 === 0 ? "bg-blue-50 border-blue-500" : "bg-green-50 border-green-500"} p-4 rounded-xl border-l-4`}>
                         <p className="text-sm text-gray-800">
                            <span className={`font-bold ${idx % 2 === 0 ? "text-blue-700" : "text-green-700"}`}>{project.title}:</span> {project.description?.substring(0, 80) || "Making a positive impact in the community."}...
                         </p>
                      </div>
                  )) : (
                      <div className="text-center py-4 text-gray-500">Add a project to see your impact summary.</div>
                  )}
               </div>
            </div>

         </div>

         {/* Right Sidebar (1/3) */}
         <div className="space-y-8">
            
            {/* Upcoming Events */}
            <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
               <h3 className="text-lg font-bold text-gray-900 mb-6">Upcoming Events</h3>
               <div className="space-y-6">
                  {events.length > 0 ? events.map((event, i) => (
                     <div key={i} className="flex items-start gap-4">
                        <div className="p-3 bg-blue-50 rounded-xl text-blue-600">
                           <Calendar className="w-5 h-5" />
                        </div>
                        <div>
                           <h4 className="text-sm font-bold text-gray-900">{event.title}</h4>
                           <p className="text-xs text-gray-500 mt-1">{formatDate(event.date)}</p>
                        </div>
                     </div>
                  )) : (
                     <p className="text-sm text-gray-500">No upcoming events scheduled.</p>
                  )}
                  
                  <div className="flex gap-2 mt-4">
                     <Link href="/dashboard/events/new" className="flex-1 text-center bg-[#0ea5e9] text-white py-2 rounded-lg text-sm font-medium hover:bg-sky-600 transition-colors btn-press">
                        Add Event
                     </Link>
                     <Link href="/dashboard/events" className="flex-1 text-center border border-gray-200 text-gray-600 py-2 rounded-lg text-sm font-medium hover:bg-gray-50 transition-colors btn-press">
                        View Calendar
                     </Link>
                  </div>
               </div>
            </div>

            {/* Documents & Compliance */}
            <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
               <div className="flex justify-between items-center mb-6">
                   <h3 className="text-lg font-bold text-gray-900">Recent Documents</h3>
               </div>
               <div className="space-y-4">
                  {(data as any).recentDocuments?.length > 0 ? (data as any).recentDocuments.slice(0, 3).map((doc: any, i: number) => (
                      <div key={i} className="flex items-center justify-between p-3 bg-gray-50 rounded-xl hover:bg-gray-100 transition-colors cursor-pointer" onClick={() => window.open(`/api/documents/${doc.id}`, '_blank')}>
                         <div className="flex items-center gap-3">
                            {doc.status === 'verified' ? <CheckCircle2 className="w-5 h-5 text-green-500" /> : 
                             doc.status === 'pending' ? <Clock className="w-5 h-5 text-blue-500" /> : 
                             <AlertCircle className="w-5 h-5 text-red-500" />}
                            <span className="text-sm font-medium text-gray-700 truncate max-w-[150px]">{doc.name}</span>
                         </div>
                         <ChevronRight className="w-4 h-4 text-gray-400" />
                      </div>
                  )) : (
                      <div className="text-center py-4 text-xs text-gray-400">No documents uploaded yet.</div>
                  )}

                  <Link href="/dashboard/documents" className="w-full bg-[#0ea5e9] text-white py-3 rounded-lg text-sm font-medium hover:bg-sky-600 transition-colors mt-2 flex items-center justify-center gap-2 btn-press shadow-sm">
                     <UploadCloud className="w-4 h-4" /> Go to Documents
                  </Link>
               </div>
            </div>

            {/* Achievements */}
            <div className="bg-white rounded-2xl p-6 shadow-sm border border-gray-100">
               <h3 className="text-lg font-bold text-gray-900 mb-6">Our Achievements</h3>
               
               {(data as any).achievements?.length > 0 ? (data as any).achievements.map((ach: any, i: number) => (
                   <div key={i} className="bg-yellow-50 rounded-xl p-4 flex items-center gap-4 mb-3">
                      <div className="w-12 h-12 bg-white rounded-full flex items-center justify-center shadow-sm text-yellow-500 shrink-0">
                         <Trophy className="w-6 h-6" />
                      </div>
                      <div>
                         <h4 className="font-bold text-gray-900 text-sm">{ach.title}</h4>
                         <p className="text-xs text-gray-500">{ach.year || 'Winner'}</p>
                      </div>
                   </div>
               )) : (
                   <div className="text-center py-6 text-gray-400 text-sm">No awards registered yet.</div>
               )}
               <Link href="/dashboard/awards" className="text-xs text-blue-600 hover:underline mt-2 inline-block">Manage Awards</Link>
            </div>

         </div>
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";
import { 
  Plus,
  Calendar,
  MapPin,
  Users,
  Eye,
  Trash2,
  X
} from "lucide-react";

import { createEvent, deleteEvent } from "@/actions/ngo-features";
import { useRouter } from "next/navigation";

export default function EventsClient({ initialData, initialStats }: { initialData: any[], initialStats: any }) {
  const router = useRouter();
  const [data, setData] = useState(initialData);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState<any>(null);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
      name: "",
      date: "",
      location: "",
      expectedBeneficiaries: "",
      description: ""
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
      setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      setIsSubmitting(true);
      try {
          const result = await createEvent(formData);
          if (result.success) {
              setIsModalOpen(false);
              setFormData({ name: "", date: "", location: "", expectedBeneficiaries: "", description: "" });
              router.refresh();
              alert("Event added successfully!");
          } else {
              alert("Failed: " + result.error);
          }
      } catch (err) {
          console.error(err);
      } finally {
          setIsSubmitting(false);
      }
  };

  const handleDelete = async (id: number) => {
      if(!confirm("Are you sure you want to delete this event?")) return;
      try {
          const result = await deleteEvent(id);
          if (result.success) {
              router.refresh();
              alert("Event deleted successfully");
          } else {
              alert("Failed to delete: " + result.error);
          }
      } catch (err) {
          console.error(err);
          alert("An error occurred");
      }
  };

  return (
    <div className="p-8 space-y-8 relative">
      <div className="flex justify-between items-start">
         <div>
          <h1 className="text-2xl font-bold text-gray-900">Events & Activities</h1>
          <p className="text-gray-500">Manage your upcoming and past events</p>
        </div>
         <button 
           onClick={() => setIsModalOpen(true)}
           className="flex items-center gap-2 px-4 py-2 text-white bg-[#0EA5E9] rounded-lg hover:bg-[#0284c7]"
         >
            <Plus className="w-4 h-4" />
            Create Event
          </button>
      </div>

       <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
             <h3 className="text-lg font-bold text-gray-900">{initialStats.total}</h3>
             <p className="text-gray-500 text-sm">Total Events</p>
          </div>
          <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
             <h3 className="text-lg font-bold text-blue-600">{initialStats.upcoming}</h3>
             <p className="text-gray-500 text-sm">Upcoming</p>
          </div>
           <div className="bg-white p-6 rounded-xl border border-gray-100 shadow-sm">
             <h3 className="text-lg font-bold text-green-600">{initialStats.completed}</h3>
             <p className="text-gray-500 text-sm">Completed</p>
          </div>
       </div>

       <div className="grid grid-cols-1 gap-4">
          {data.map((event) => (
             <div key={event.id} className="bg-white p-6 rounded-xl border border-gray-100 flex justify-between items-center hover:shadow-md transition-shadow">
                 <div>
                    <h3 className="text-lg font-bold text-gray-900">{event.title}</h3>
                    <div className="flex gap-4 mt-2 text-sm text-gray-500">
                        <div className="flex items-center gap-1">
                            <Calendar className="w-4 h-4" />
                            {new Date(event.date).toLocaleDateString()}
                        </div>
                         <div className="flex items-center gap-1">
                            <MapPin className="w-4 h-4" />
