"use client";

import { useSession, signOut } from "next-auth/react";
import Image from "next/image";
import { Bell, Search, ChevronDown, LogOut, Menu, Trash2 } from "lucide-react";
import { useState, useRef, useEffect, useCallback } from "react";
import Link from "next/link";
import { getNotifications, markNotificationsAsRead } from "@/actions/notifications";
import { Notification } from "@/lib/schema";

export default function TopHeader({ onMenuClick }: { onMenuClick?: () => void }) {
  const { data: session } = useSession();
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);
  const profileRef = useRef<HTMLDivElement>(null);
  const notifRef = useRef<HTMLDivElement>(null);

  const fetchNotes = useCallback(async () => {
      const res = await getNotifications();
      if (res?.data) {
          setNotifications(res.data);
      }
  }, []);

  useEffect(() => {
      fetchNotes();
      const interval = setInterval(fetchNotes, 10000); 
      return () => clearInterval(interval);
  }, [fetchNotes]);

  const unreadCount = notifications.filter(n => !n.isRead).length;

  const handleOpenDropdown = async () => {
      setIsNotificationOpen(!isNotificationOpen);
      if (!isNotificationOpen && unreadCount > 0) {
          await markNotificationsAsRead();
          setNotifications(notifications.map(n => ({...n, isRead: true})));
      }
  };

  const handleClearAll = () => {
      setNotifications([]);
      setIsNotificationOpen(false);
  };

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (profileRef.current && !profileRef.current.contains(event.target as Node)) {
        setIsProfileOpen(false);
      }
      if (notifRef.current && !notifRef.current.contains(event.target as Node)) {
        setIsNotificationOpen(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const formatTime = (dateStr: string | Date) => {
    const d = new Date(dateStr);
    const now = new Date();
    const diff = now.getTime() - d.getTime();
    const mins = Math.floor(diff / 60000);
    if (mins < 1) return "Just now";
    if (mins < 60) return `${mins}m ago`;
    const hrs = Math.floor(mins / 60);
    if (hrs < 24) return `${hrs}h ago`;
    return d.toLocaleDateString();
  };

  return (
    <header className="h-16 bg-white border-b border-gray-100/80 flex items-center justify-between px-6 sticky top-0 z-40">
      {/* Left: Greeting/Breadcrumb */}
      <div className="flex items-center gap-4">
        <button 
          onClick={onMenuClick}
          className="md:hidden p-2 -ml-2 text-gray-500 hover:bg-gray-100 rounded-xl transition-colors"
        >
          <Menu className="w-5 h-5" />
        </button>
        <h1 className="text-lg font-semibold text-gray-800">
          DASHBOARD
        </h1>
      </div>

      {/* Right: Actions & Profile */}
      <div className="flex items-center gap-3">
        {/* Search Bar */}
        <div className="hidden md:flex items-center bg-gray-50 rounded-xl px-4 py-2 border border-gray-100 focus-within:border-blue-200 focus-within:ring-2 focus-within:ring-blue-50 transition-all w-56">
          <Search className="w-4 h-4 text-gray-400" />
          <input 
            type="text"
            placeholder="Search..."
            className="bg-transparent border-none outline-none text-sm ml-2 w-full text-gray-600 placeholder:text-gray-400"
          />
        </div>

        {/* Notifications */}
        <div className="relative" ref={notifRef}>
            <button 
              onClick={handleOpenDropdown}
              className="relative p-2.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-xl transition-all duration-200 btn-press"
            >
              <Bell className="w-[18px] h-[18px]" />
              {unreadCount > 0 && (
                  <span className="absolute top-1 right-1 min-w-[18px] h-[18px] bg-red-500 rounded-full ring-2 ring-white flex items-center justify-center text-[9px] font-bold text-white shadow-sm px-1">
                      {unreadCount > 9 ? '9+' : unreadCount}
                  </span>
              )}
            </button>
            {isNotificationOpen && (
                <div className="absolute top-full right-0 mt-2 w-[340px] bg-white rounded-2xl shadow-xl border border-gray-100/80 text-sm z-50 animate-dropdown-in overflow-hidden">
                    <div className="flex items-center justify-between px-4 py-3 border-b border-gray-100/60">
                        <h4 className="font-semibold text-gray-900 text-sm">Notifications</h4>
                        {notifications.length > 0 && (
                            <button onClick={handleClearAll} className="text-[11px] text-gray-400 hover:text-red-500 transition-colors flex items-center gap-1">
                                <Trash2 className="w-3 h-3" /> Clear all
                            </button>
                        )}
                    </div>
                    <div className="max-h-80 overflow-y-auto scrollbar-hide divide-y divide-gray-50">
                        {notifications.length === 0 ? (
                            <div className="flex flex-col items-center justify-center py-10 px-4">
                                <div className="w-12 h-12 rounded-full bg-gray-100 flex items-center justify-center mb-3">
                                    <Bell className="w-5 h-5 text-gray-300" />
                                </div>
                                <p className="text-sm font-medium text-gray-400">All caught up!</p>
                                <p className="text-[11px] text-gray-300 mt-0.5">No new notifications</p>
                            </div>
                        ) : (
                            notifications.map(n => (
                                <div key={n.id} className="px-4 py-3 hover:bg-gray-50/60 transition-colors flex gap-3 items-start">
                                    <div className={`w-2 h-2 rounded-full mt-1.5 flex-shrink-0 ${!n.isRead ? 'bg-blue-500' : 'bg-gray-200'}`} />
                                    <div className="flex-1 min-w-0">
                                        <p className={`text-[13px] font-medium ${!n.isRead ? 'text-gray-900' : 'text-gray-600'} line-clamp-1`}>{n.title}</p>
                                        <p className="text-[11px] text-gray-400 mt-0.5 line-clamp-2">{n.message}</p>
                                        <p className="text-[10px] text-gray-300 mt-1">{formatTime(n.createdAt)}</p>
                                    </div>
                                </div>
                            ))
                        )}
                    </div>
                </div>
            )}
        </div>

        {/* Divider */}
        <div className="w-px h-8 bg-gray-100 hidden md:block" />

        {/* Profile Dropdown */}
        <div className="relative" ref={profileRef}>
          <button 
            onClick={() => setIsProfileOpen(!isProfileOpen)}
            className="flex items-center gap-2.5 hover:bg-gray-50 p-1.5 pr-3 rounded-xl transition-all duration-200 border border-transparent hover:border-gray-100"
          >
            <div className="w-9 h-9 rounded-xl overflow-hidden border border-gray-200 shadow-sm">
              <Image
                src={session?.user?.image || `https://ui-avatars.com/api/?name=${session?.user?.name}&background=random`}
                alt="Profile"
                width={36}
                height={36}
                className="w-full h-full object-cover"
              />
            </div>
            <div className="hidden md:block text-left">
              <p className="text-[13px] font-semibold text-gray-700 leading-none">
                {session?.user?.name}
              </p>
              <p className="text-[10px] text-blue-600 font-medium bg-blue-50 px-1.5 py-0.5 rounded-full inline-block mt-1">
                NGO Admin
              </p>
            </div>
            <ChevronDown className={`w-3.5 h-3.5 text-gray-400 transition-transform duration-200 ${isProfileOpen ? 'rotate-180' : ''}`} />
          </button>

          {isProfileOpen && (
            <div className="absolute right-0 mt-2 w-52 bg-white rounded-2xl shadow-xl border border-gray-100/80 py-1.5 animate-dropdown-in">
              <Link href="/dashboard/profile" className="block px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 transition-colors">
                My Profile
              </Link>
              <Link href="/dashboard/settings" className="block px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 transition-colors">
                Settings
              </Link>
              <div className="h-px bg-gray-100 my-1"></div>
              <button 
                onClick={() => signOut({ callbackUrl: '/' })}
                className="w-full text-left px-4 py-2.5 text-sm text-red-600 hover:bg-red-50 transition-colors flex items-center gap-2 rounded-b-2xl"
              >
                <LogOut className="w-4 h-4" />
                Sign Out
              </button>
            </div>
          )}
        </div>
      </div>
    </header>
  );
}

"use client";

import { useState } from "react";
import { 
  Plus, 
  Search, 
  Download, 
  Users, 
  Clock, 
  CheckCircle2, 
  Star,
  Mail,
  Phone,
  MapPin,
  Calendar,
  Eye,
  Trash2,
  Check
} from "lucide-react";

import { createVolunteer, deleteVolunteer } from "@/actions/ngo-features";
import { useRouter } from "next/navigation";

export default function VolunteersClient({ initialData, initialStats }: { initialData: any[], initialStats: any }) {
  const router = useRouter();
  const [data, setData] = useState(initialData);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [selectedVolunteer, setSelectedVolunteer] = useState<any>(null);
  const [formData, setFormData] = useState({
     name: "",
     email: "",
     phone: "",
     location: "",
     skills: "",
     availability: "Weekends"
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
     setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    try {
       const result = await createVolunteer(formData);
       if (result.success) {
           setIsModalOpen(false);
           setFormData({ name: "", email: "", phone: "", location: "", skills: "", availability: "Weekends" });
           router.refresh(); 
           alert("Volunteer registered successfully!");
       } else {
           alert("Failed: " + result.error);
       }
    } catch (err) {
        console.error(err);
        alert("An error occurred.");
    } finally {
        setIsSubmitting(false);
    }
  };

  const handleDelete = async (id: number) => {
    if(!confirm("Are you sure you want to delete this volunteer?")) return;
    try {
        const result = await deleteVolunteer(id);
        if (result.success) {
            router.refresh(); // Refresh to update list
            alert("Volunteer deleted successfully");
        } else {
           alert("Failed to delete: " + result.error);
        }
    } catch (err) {
        console.error(err);
        alert("An error occurred");
    }
  };

  return (
    <div className="p-8 space-y-8 relative">
      {/* Header */}
      <div className="flex justify-between items-start">
        <div>
          <h1 className="text-2xl font-bold text-gray-900">Volunteer Registration</h1>
          <p className="text-gray-500">Manage your volunteer community</p>
        </div>
        <div className="flex gap-3">
          <button className="flex items-center gap-2 px-4 py-2 text-gray-600 bg-white border border-gray-200 rounded-lg hover:bg-gray-50">
            <Download className="w-4 h-4" />
            Export Data
          </button>
          <button 
            onClick={() => setIsModalOpen(true)}
            className="flex items-center gap-2 px-4 py-2 text-white bg-[#0EA5E9] rounded-lg hover:bg-[#0284c7]"
          >
            <Plus className="w-4 h-4" />
            Register Volunteer
          </button>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <StatsCard 
          title="Total Volunteers" 
          value={initialStats?.total || 0} 
          icon={Users}
          color="bg-[#0EA5E9]" 
        />
        <StatsCard 
          title="Active Volunteers" 
          value={initialStats?.active || 0} 
          icon={CheckCircle2}
          color="bg-[#0284c7]"
        />
        <StatsCard 
          title="Pending Approval" 
          value={initialStats?.pending || 0} 
          icon={Clock}
          color="bg-[#0369a1]"
        />
        <StatsCard 
          title="Total Hours" 
          value={initialStats?.totalHours || 0} 
          icon={Star}
          color="bg-[#075985]"
        />
      </div>

      {/* Search & Filter */}
      <div className="flex gap-4">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400 w-5 h-5" />
          <input
            type="text"
            placeholder="Search volunteers by name..."
            className="w-full pl-10 pr-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#0EA5E9]"
          />
        </div>
        <select 
          className="px-4 py-2 border border-gray-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#0EA5E9] bg-white text-gray-600 min-w-[150px]"
        >
          <option value="All">All Status</option>
          <option value="Active">Active</option>
          <option value="Pending">Pending</option>
        </select>
      </div>

      {/* Volunteer Cards Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
         {data.map((volunteer, index) => (
             <VolunteerCard 
                key={volunteer.id || index} 
                volunteer={volunteer} 
                index={index} 
                onView={() => setSelectedVolunteer(volunteer)} 
                onDelete={() => handleDelete(volunteer.id)}
             />
         ))}
         {data.length === 0 && (
            <div className="col-span-3 text-center py-12 text-gray-500">
               No volunteers found.
            </div>
         )}
      </div>

      {/* Register Volunteer Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
           <div className="bg-white rounded-2xl p-6 w-full max-w-2xl max-h-[90vh] overflow-y-auto">
              <div className="flex justify-between items-center mb-6">
                 <h2 className="text-xl font-bold text-gray-900">Register New Volunteer</h2>
                 <button onClick={() => setIsModalOpen(false)} className="text-gray-500 hover:text-gray-700">
                    <Plus className="w-6 h-6 rotate-45" />
                 </button>
              </div>
              
              <form onSubmit={handleSubmit} className="space-y-4">
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                       <label className="block text-sm font-medium text-gray-700 mb-1">Full Name *</label>
                       <input required name="name" value={formData.name} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none" placeholder="Enter full name" />
                    </div>
                    <div>
                       <label className="block text-sm font-medium text-gray-700 mb-1">Email *</label>
                       <input required type="email" name="email" value={formData.email} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none" placeholder="email@example.com" />
                    </div>
                 </div>

                 <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                       <label className="block text-sm font-medium text-gray-700 mb-1">Phone</label>
                       <input name="phone" value={formData.phone} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none" placeholder="+91 XXXXX XXXXX" />
                    </div>
                    <div>
                       <label className="block text-sm font-medium text-gray-700 mb-1">Location</label>
                       <input name="location" value={formData.location} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none" placeholder="City" />
                    </div>
                 </div>

                 <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Skills (comma separated)</label>
                    <input name="skills" value={formData.skills} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none" placeholder="Teaching, Event Management, IT Support" />
                 </div>

                 <div>
                    <label className="block text-sm font-medium text-gray-700 mb-1">Availability</label>
                    <select name="availability" value={formData.availability} onChange={handleInputChange} className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-[#0EA5E9] outline-none">
                       <option value="Weekends">Weekends</option>
                       <option value="Weekdays">Weekdays</option>
                       <option value="Anytime">Anytime</option>
                    </select>
                 </div>

                 <div className="flex gap-3 pt-4 border-t">
                    <button type="button" onClick={() => setIsModalOpen(false)} className="flex-1 px-4 py-2 border rounded-lg text-gray-700 hover:bg-gray-50">Cancel</button>
                    <button type="submit" disabled={isSubmitting} className="flex-1 px-4 py-2 bg-[#0EA5E9] text-white rounded-lg hover:bg-[#0284c7] disabled:opacity-50">
                       {isSubmitting ? "Registering..." : "Register Volunteer"}
                    </button>
                 </div>
              </form>
           </div>
        </div>
      )}

      {/* Volunteer Details Modal */}
      {selectedVolunteer && (
          <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
              <div className="bg-white rounded-2xl p-6 w-full max-w-lg">
                  <div className="flex justify-between items-center mb-6">
                      <h2 className="text-xl font-bold text-gray-900">Volunteer Details</h2>
                      <button onClick={() => setSelectedVolunteer(null)} className="text-gray-500 hover:text-gray-700">
                          <Plus className="w-6 h-6 rotate-45" />
                      </button>
                  </div>
                  
                  <div className="flex items-center gap-4 mb-6">
                      <div className="w-16 h-16 bg-[#075985] rounded-xl flex items-center justify-center text-white font-bold text-2xl">
                          {selectedVolunteer.name?.charAt(0)}
                      </div>
                      <div>
                          <h3 className="text-xl font-bold text-gray-900">{selectedVolunteer.name}</h3>
                          <div className="flex items-center gap-3 mt-1">
                              <span className="bg-green-100 text-green-700 px-2 py-0.5 rounded text-xs font-medium">
                                  {selectedVolunteer.status || 'Active'}
                              </span>
                              <div className="flex items-center gap-1 text-yellow-500 text-sm">
                                  <Star className="w-4 h-4 fill-current" />
                                  <span>4.8</span>
                              </div>
                          </div>
                      </div>
                  </div>

                  <div className="grid grid-cols-2 gap-6 mb-6">
                      <div>
                          <p className="text-sm text-gray-500 mb-1">Email</p>
                          <p className="font-medium text-gray-900 truncate">{selectedVolunteer.email}</p>
                      </div>
                       <div>
                          <p className="text-sm text-gray-500 mb-1">Phone</p>
                          <p className="font-medium text-gray-900">{selectedVolunteer.phone || 'N/A'}</p>
                      </div>
                       <div>
                          <p className="text-sm text-gray-500 mb-1">Location</p>
                          <p className="font-medium text-gray-900">{selectedVolunteer.location || 'N/A'}</p>
                      </div>
                       <div>
                          <p className="text-sm text-gray-500 mb-1">Availability</p>
                          <p className="font-medium text-gray-900">{selectedVolunteer.availability || 'Weekends'}</p>
                      </div>
                       <div>
                          <p className="text-sm text-gray-500 mb-1">Hours Contributed</p>
                          <p className="font-medium text-gray-900">120 hours</p>
                      </div>
                       <div>
                          <p className="text-sm text-gray-500 mb-1">Join Date</p>
                          <p className="font-medium text-gray-900">{new Date(selectedVolunteer.createdAt).toLocaleDateString()}</p>
                      </div>
                  </div>

                  <div className="mb-6">
                      <p className="text-sm text-gray-500 mb-2">Skills</p>
                      <div className="flex gap-2 flex-wrap">
                          {selectedVolunteer.skills ? selectedVolunteer.skills.split(',').map((skill: string) => (
                              <span key={skill} className="px-3 py-1 bg-blue-50 text-blue-600 rounded-full text-sm">
                                  {skill.trim()}
                              </span>
                          )) : <span className="text-gray-400 text-sm">No skills listed</span>}
                      </div>
                  </div>

                  <button 
                      onClick={() => setSelectedVolunteer(null)}
                      className="w-full py-3 bg-[#0EA5E9] text-white rounded-xl font-medium hover:bg-[#0284c7]"
                  >
                      Close
                  </button>
              </div>
          </div>
      )}
    </div>
  );
}

function StatsCard({ title, value, icon: Icon, color }: any) {
  return (
    <div className={`${color} text-white rounded-xl p-6 relative overflow-hidden flex items-center justify-between`}>
      <div className="relative z-10">
         <Icon className="w-8 h-8 mb-3 opacity-80" />
         <p className="text-blue-100 text-sm font-medium mb-1">{title}</p>
      </div>
      <div className="bg-white/20 px-4 py-2 rounded-lg backdrop-blur-sm">
         <span className="text-2xl font-bold">{value}</span>
      </div>
    </div>
  );
}

function VolunteerCard({ volunteer, index, onView, onDelete }: { volunteer: any, index: number, onView: () => void, onDelete: () => void }) {
    // Determine status
    const status = volunteer.status || "Pending"; 
    const isPending = status === "Pending";
    const location = volunteer.location || "Location not specified";
    const joined = new Date(volunteer.createdAt).toLocaleDateString("en-US", { month: 'short', year: 'numeric' });
    
    // Fallbacks
    const name = volunteer.name || "Unknown Volunteer";
    const email = volunteer.email || "No email";
    const phone = volunteer.phone || "No phone";
    
    return (
        <div className="bg-white border border-gray-100 rounded-xl p-6 shadow-sm hover:shadow-md transition-shadow">
            <div className="flex justify-between items-start mb-4">
               <div className="flex items-center gap-3">
                  <div className={`w-12 h-12 rounded-lg flex items-center justify-center text-white font-bold text-lg ${index % 2 === 0 ? 'bg-[#0f4c81]' : 'bg-[#0EA5E9]'}`}>
                      {name.charAt(0)}
                  </div>
                  <div>
                      <h3 className="font-bold text-gray-900">{name}</h3>
                      <p className="text-xs text-gray-400">Volunteer</p>
                  </div>
               </div>
               <span className={`px-3 py-1 rounded-full text-xs font-medium ${isPending ? 'bg-orange-100 text-orange-700' : 'bg-green-100 text-green-700'}`}>
                   {status}
               </span>
            </div>

            <div className="space-y-2 mb-6">
                <div className="flex items-center gap-2 text-sm text-gray-500">
                    <Mail className="w-4 h-4" />
                    <span className="truncate">{email}</span>
                </div>
                 <div className="flex items-center gap-2 text-sm text-gray-500">
                    <Phone className="w-4 h-4" />
                    <span>{phone}</span>
                </div>
                 <div className="flex items-center gap-2 text-sm text-gray-500">
                    <MapPin className="w-4 h-4" />
                    <span>{location}</span>
                </div>
                  <div className="flex items-center gap-2 text-sm text-gray-500">
                    <Calendar className="w-4 h-4" />
                    <span>{volunteer.availability || "Availability not set"}</span> 
                </div>
            </div>

            <div className="flex gap-2 flex-wrap mb-6 min-h-[24px]">
                {volunteer.skills ? volunteer.skills.split(',').slice(0,3).map((tag:string) => (
                    <span key={tag} className="px-2 py-1 bg-blue-50 text-blue-600 rounded text-xs">
                        {tag.trim()}
                    </span>
                )) : (
                     <span className="text-xs text-gray-400">No specific skills listed</span>
                )}
            </div>

            <div className="flex justify-between items-center pt-4 border-t border-gray-50 mb-4">
                  <div className="text-center w-full">
                     <p className="text-sm font-bold text-gray-900">{joined}</p>
                     <p className="text-xs text-gray-400">Joined</p>
                 </div>
            </div>

            <div className="flex gap-2">
                <button 
                  onClick={onView}
                  className="flex-1 py-2 text-sm font-medium text-blue-600 bg-blue-50 hover:bg-blue-100 rounded-lg flex items-center justify-center gap-2"
                >
                    <Eye className="w-4 h-4" />
                    View
                </button>
                 {isPending ? (
                      <button className="flex-1 py-2 text-sm font-medium text-green-600 bg-green-50 hover:bg-green-100 rounded-lg flex items-center justify-center gap-2">
                        <Check className="w-4 h-4" />
                        Approve
                    </button>
                 ) : (
                    <button 
                        onClick={onDelete} 
                        className="p-2 text-red-500 hover:bg-red-50 rounded-lg"
                    >
                        <Trash2 className="w-4 h-4" />
                    </button>
                 )}
            </div>
        </div>
    )
}

"use client";

import { Component, ReactNode } from "react";

interface Props {
  children: ReactNode;
}

interface State {
  hasError: boolean;
}

/**
 * ✅ NEW: Error boundary for graceful Three.js failures
 * Place this in: components/globe/GlobeErrorBoundary.tsx
 */
export class GlobeErrorBoundary extends Component<Props, State> {
  constructor(props: Props) {
    super(props);
    this.state = { hasError: false };
  }

  static getDerivedStateFromError() {
    return { hasError: true };
  }

  componentDidCatch(error: Error, info: any) {
    console.error("Globe render error:", error, info);
  }

  render() {
    if (this.state.hasError) {
      return (
        <div className="w-full h-full flex items-center justify-center bg-gray-100 rounded-xl">
          <div className="text-center text-gray-600 px-4">
            <p className="text-lg font-semibold mb-2">
              Unable to load 3D globe
            </p>
            <p className="text-sm">
              Please refresh the page or check your browser compatibility
            </p>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

"use client";

import { useState, useEffect } from "react";
import { Search, SlidersHorizontal } from "lucide-react";
import { useGlobe } from "@/context/GlobeContext";
import FilterModal from "../layout/FilterModal";
import { motion, AnimatePresence } from "framer-motion";

export default function GlobeSearch() {
  const [query, setQuery] = useState("");
  const [debouncedQuery, setDebouncedQuery] = useState("");
  const [category, setCategory] = useState<string>("All");
  const [showResults, setShowResults] = useState(false);
  const [isFilterModalOpen, setIsFilterModalOpen] = useState(false);
  
  const { setSelectedLocation, setViewMode, allNgos } = useGlobe();

  useEffect(() => {
    const timer = setTimeout(() => {
      setDebouncedQuery(query);
    }, 300);
    return () => clearTimeout(timer);
  }, [query]);

  const filteredNgos = allNgos
    .filter((ngo) => {
      const q = debouncedQuery.trim().toLowerCase();
      
      if (category !== "All" && !ngo.category.includes(category) && ngo.category !== category) return false;
      if (category === "All" && !q) return false;
      
      if (q) {
        const textMatch =
          ngo.name.toLowerCase().includes(q) ||
          (ngo.city && ngo.city.toLowerCase().includes(q)) ||
          ngo.state.toLowerCase().includes(q);
        
        if (!textMatch) return false;
      }
      return true;
    })
    .slice(0, 5);

  function handleSelect(ngo: any) {
    setSelectedLocation(ngo);
    setViewMode("map");
    setShowResults(false);
    setQuery("");
  }

  function handleSearchSubmit() {
    if (filteredNgos.length > 0) {
      handleSelect(filteredNgos[0]);
    }
  }

  return (
    <div className="relative w-full z-40">
      <div className="flex items-center gap-3">
        <div className="relative flex-1">
            <div className="flex h-[56px] items-center gap-3 rounded-xl border border-gray-200 bg-white px-4 shadow-sm focus-within:ring-2 focus-within:ring-blue-100 focus-within:border-blue-400 transition-all duration-200">
            <Search className="h-5 w-5 text-gray-400" />
            <input
                value={query}
                onChange={(e) => {
                setQuery(e.target.value);
                setShowResults(true);
                }}
                onFocus={() => setShowResults(true)}
                onKeyDown={(e) => e.key === "Enter" && handleSearchSubmit()}
                className="flex-1 bg-transparent text-[16px] text-gray-900 outline-none placeholder:text-gray-400"
                placeholder="Search NGOs on the Global Map..."
            />
            </div>

            <AnimatePresence>
            {showResults && (debouncedQuery || category !== "All") && (
                <motion.div
                initial={{ opacity: 0, y: 10 }}
                animate={{ opacity: 1, y: 0 }}
                exit={{ opacity: 0, y: 10 }}
                className="absolute top-[64px] left-0 w-full bg-white rounded-xl shadow-xl border border-gray-100 overflow-hidden py-2 z-50 max-h-[400px] overflow-y-auto"
                >
                {filteredNgos.length > 0 ? (
                    filteredNgos.map((ngo) => (
                    <div
                        key={ngo.id}
                        onClick={() => handleSelect(ngo)}
                        className="px-4 py-3 hover:bg-gray-50 cursor-pointer border-b border-gray-50 last:border-none flex justify-between items-center"
                    >
                        <div>
                        <p className="font-medium text-gray-900">{ngo.name}</p>
                        <p className="text-sm text-gray-500">{ngo.city}, {ngo.state}</p>
                        </div>
                        <span className="text-xs bg-blue-50 text-blue-600 px-2 py-1 rounded-full">
                        {ngo.category}
                        </span>
                    </div>
                    ))
                ) : (
                    <div className="px-4 py-3 text-gray-500 text-sm">No results found</div>
                )}
                </motion.div>
            )}
            </AnimatePresence>
        </div>

        <button 
            onClick={() => setIsFilterModalOpen(true)}
            className={`flex items-center gap-2 h-[56px] px-6 rounded-xl border transition-all duration-200 shadow-sm
                ${category !== 'All' 
                ? 'border-blue-500 bg-blue-50 text-blue-700' 
                : 'border-gray-200 bg-white text-gray-600 hover:bg-gray-50'
                }`}
        >
            <span className="text-base font-medium hidden sm:inline">Filter</span>
            <SlidersHorizontal className="h-5 w-5" />
        </button>
      </div>

      <FilterModal 
        isOpen={isFilterModalOpen} 
        onClose={() => setIsFilterModalOpen(false)}
        selectedCategory={category}
        onSelectCategory={setCategory}
        onApply={() => {
            setIsFilterModalOpen(false);
            if (category !== "All") setShowResults(true);
        }}
      />
      
      {showResults && (
        <div 
            className="fixed inset-0 z-30 bg-transparent" 
            onClick={() => setShowResults(false)}
        />
      )}
    </div>
  );
}

