  });

  const [map, setMap] = useState<google.maps.Map | null>(null);
  const searchBoxRef = useRef<google.maps.places.SearchBox | null>(null);

  // Default to India center if no prop provided
  const [selectedLocation, setSelectedLocation] = useState<{ lat: number; lng: number }>(
    initialLat && initialLng ? { lat: initialLat, lng: initialLng } : { lat: 20.5937, lng: 78.9629 }
  );

  // mapCenter state to control the map's center properly when searching
  const [mapCenter, setMapCenter] = useState<{ lat: number; lng: number }>(
      initialLat && initialLng ? { lat: initialLat, lng: initialLng } : { lat: 20.5937, lng: 78.9629 }
  );

  const onLoad = useCallback((map: google.maps.Map) => {
    setMap(map);
  }, []);

  const onUnmount = useCallback(() => {
    setMap(null);
  }, []);

  const onSearchLoad = (ref: google.maps.places.SearchBox) => {
    searchBoxRef.current = ref;
  };

  const onPlacesChanged = () => {
    if (searchBoxRef.current) {
        const places = searchBoxRef.current.getPlaces();
        if (places && places.length > 0) {
            const place = places[0];
            if (place.geometry && place.geometry.location) {
                const newLocation = {
                    lat: place.geometry.location.lat(),
                    lng: place.geometry.location.lng(),
                };
                setSelectedLocation(newLocation);
                setMapCenter(newLocation); // Pan map to new location
                // If map is loaded, we can also smooth pan
                map?.panTo(newLocation);
                map?.setZoom(15); // Zoom in when specific place found
            }
        }
    }
  };

  const handleMapClick = (e: google.maps.MapMouseEvent) => {
    if (e.latLng) {
      setSelectedLocation({
        lat: e.latLng.lat(),
        lng: e.latLng.lng(),
      });
    }
  };

  if (!isLoaded) {
    return (
      <div className="w-full h-[400px] flex items-center justify-center bg-gray-100 rounded-xl">
        <div className="animate-spin rounded-full h-10 w-10 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div className="relative w-full h-[500px] rounded-xl overflow-hidden">
      <GoogleMap
        mapContainerStyle={containerStyle}
        center={mapCenter}
        zoom={5}
        onLoad={onLoad}
        onUnmount={onUnmount}
        onClick={handleMapClick}
        options={{
            disableDefaultUI: false,
            zoomControl: true,
            fullscreenControl: false,
            streetViewControl: false,
        }}
      >
        <MarkerF position={selectedLocation} />
        
        {/* Search Box - Centered Top */}
        <div className="absolute top-4 left-1/2 -translate-x-1/2 w-[90%] max-w-md z-10">
            <StandaloneSearchBox
                onLoad={onSearchLoad}
                onPlacesChanged={onPlacesChanged}
            >
                <div className="relative shadow-lg rounded-lg">
                    <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                        <Search className="h-5 w-5 text-gray-400" />
                    </div>
                    <input
                        type="text"
                        placeholder="Search for a location..."
                        className="block w-full pl-10 pr-3 py-3 border-none rounded-lg leading-5 bg-white text-gray-900 placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-blue-500 sm:text-sm"
                        style={{ boxShadow: "0 2px 6px rgba(0,0,0,0.1)" }}
                    />
                </div>
            </StandaloneSearchBox>
        </div>

      </GoogleMap>

      {/* Control Panel Overlay */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 bg-white px-6 py-4 rounded-xl shadow-lg flex flex-col gap-3 w-[90%] max-w-md">
         <div>
            <p className="text-xs text-gray-500 font-medium uppercase mb-1">Selected Coordinates</p>
            <div className="flex gap-4 text-sm font-mono bg-gray-50 p-2 rounded border border-gray-100">
                <span>Lat: {selectedLocation.lat.toFixed(6)}</span>
                <span>Lng: {selectedLocation.lng.toFixed(6)}</span>
            </div>
         </div>
         <div className="flex gap-3 pt-2">
            <button 
                onClick={onCancel}
                className="flex-1 py-2 text-gray-600 bg-gray-100 hover:bg-gray-200 rounded-lg text-sm font-medium transition-colors"
            >
                Cancel
            </button>
            <button 
                onClick={() => onSave(selectedLocation.lat, selectedLocation.lng)}
                className="flex-1 py-2 text-white bg-blue-600 hover:bg-blue-700 rounded-lg text-sm font-medium transition-colors"
            >
                Set Location
            </button>
         </div>
      </div>
    </div>
  );
}

import { NextAuthOptions } from 'next-auth';
import CredentialsProvider from 'next-auth/providers/credentials';
import bcrypt from 'bcryptjs';
import GoogleProvider from 'next-auth/providers/google';
import LinkedInProvider from 'next-auth/providers/linkedin';
import { db } from '@/lib/db';
import { users, ngos } from '@/lib/schema';
import { eq } from 'drizzle-orm';


// Diagnostic logging
if (!process.env.NEXTAUTH_SECRET) {
  console.warn("⚠️ NEXTAUTH_SECRET is not set in environment variables. Using a fallback for development.");
}

export const authOptions: NextAuthOptions = {
  // Use env var or fallback for dev to prevent decryption errors if env is missing
  secret: process.env.NEXTAUTH_SECRET || 'fallback_secret_for_dev_only_do_not_use_in_prod',
  providers: [
    CredentialsProvider({
      name: 'Credentials',
      credentials: {
        email: { label: "Email", type: "email" },
        password: { label: "Password", type: "password" }
      },
      async authorize(credentials) {
        if (!credentials?.email || !credentials?.password) return null;

        const dbUser = await db.query.users.findFirst({
          where: eq(users.email, credentials.email),
        });

        if (!dbUser || !dbUser.password) return null;

        const passwordsMatch = await bcrypt.compare(credentials.password, dbUser.password);

        if (!passwordsMatch) return null;

        return {
          id: dbUser.id.toString(),
          name: dbUser.name,
          email: dbUser.email,
          image: null,
          role: dbUser.role as string,
        };
      }
    }),
    GoogleProvider({
      clientId: process.env.GOOGLE_CLIENT_ID || '',
      clientSecret: process.env.GOOGLE_CLIENT_SECRET || '',
    }),
    LinkedInProvider({
      clientId: process.env.LINKEDIN_CLIENT_ID || '',
      clientSecret: process.env.LINKEDIN_CLIENT_SECRET || '',
      authorization: {
        params: { scope: 'openid profile email' },
      },
      issuer: 'https://www.linkedin.com',
      jwks_endpoint: 'https://www.linkedin.com/oauth/openid/jwks',
      profile(profile) {
        return {
          id: profile.sub,
          name: profile.name,
          email: profile.email,
          image: profile.picture,
          role: 'user', // Default for type satisfaction, overridden in signIn
        };
      },
    }),
  ],
  session: {
    strategy: 'jwt',
  },
  pages: {
    signIn: '/signin',
    error: '/signin',
  },
  callbacks: {
    async signIn({ user, account }) {
      if (account?.provider === 'credentials') return true;

      if (!user.email) return false;

      let dbUser = await db.query.users.findFirst({
        where: eq(users.email, user.email),
      });

      if (!dbUser) {
        // Create new user via Social Auth - Default to NGO as per requirement
        try {
          const [newUser] = await db.insert(users).values({
            name: user.name || 'Unknown',
            email: user.email,
            image: user.image, // Save Google profile image
            role: 'ngo', // Defaulting to NGO
            provider: account?.provider || 'credentials',
            organizationName: null,
          }).returning();
          dbUser = newUser;

          // Also create a shell NGO profile for social users
          if (dbUser) {
            await db.insert(ngos).values({
              ownerId: dbUser.id,
              name: user.name ? `${user.name}'s NGO` : 'My NGO',
              verified: false,
            });
          }
        } catch (error) {
          console.error('Error creating user via Social Auth:', error);
          return false;
        }
      }

      // Inject rule into the user object so it propagates to JWT
      user.role = dbUser.role;
      user.id = dbUser.id.toString();
      // Ensure image is up to date in the session user object if it came from DB
      if (dbUser.image) {
        user.image = dbUser.image;
      }

      return true;
    },
    async jwt({ token, user }) {
      if (user) {
        token.role = user.role;
        token.id = user.id;
        token.picture = user.image;
      }
      return token;
    },
    async session({ session, token }) {
      if (session.user) {
        (session.user as any).role = token.role;
        (session.user as any).id = token.id;
      }
      return session;
    },
    async redirect({ url, baseUrl }) {
      // If the redirect URL is the homepage or signin page, redirect to onboarding flow
      if (url === baseUrl || url === `${baseUrl}/signin`) {
        return `${baseUrl}/dashboard`;
      }
      // Allows relative callback URLs
      if (url.startsWith("/")) return `${baseUrl}${url}`;
      // Allows callback URLs on the same origin
      else if (new URL(url).origin === baseUrl) return url;
      return baseUrl;
    },
  },
};

